type SortDirection = 'asc' | 'desc';
interface SortConfig {
    key: string;
    direction: SortDirection;
}

const getNestedValue = (obj: any, path: string) => {
    return path.split('.').reduce((o, key) => (o && o[key] != null ? o[key] : null), obj);
};

// Componente Compacto de Métricas (Design High Contrast)
const CompactMetricsBar: React.FC<{ metrics: any, language: Language, isExpense: boolean }> = ({ metrics, language, isExpense }) => {
    if (isExpense) return null;

    return (
        <div className="flex items-center gap-2 text-[10px] font-medium text-slate-600 dark:text-slate-300 overflow-x-auto custom-scrollbar pb-1">
            {/* Total Geral - White Pill */}
            <div className="flex items-center gap-1.5 px-3 py-1 rounded-md bg-white dark:bg-slate-800 border border-blue-200 dark:border-slate-600 whitespace-nowrap shadow-sm">
                <span className="font-bold text-slate-700 dark:text-slate-200">Total:</span>
                <span className="text-slate-600 dark:text-slate-400">{metrics.total.quantity}</span>
                <span className="text-slate-300 dark:text-slate-600 mx-0.5">|</span>
                <span className="font-mono font-bold text-slate-900 dark:text-white">{formatCurrency(metrics.total.value, language)}</span>
            </div>

            {/* Auto (Verde) - White Pill with Green Accent */}
            <div className="flex items-center gap-1.5 px-3 py-1 rounded-md bg-white dark:bg-emerald-900/20 border border-emerald-200/60 dark:border-emerald-800 whitespace-nowrap shadow-sm">
                <div className="w-1.5 h-1.5 rounded-full bg-emerald-500"></div>
                <span className="text-emerald-700 dark:text-emerald-400">Auto: {metrics.auto.quantity}</span>
                <span className="font-mono font-bold text-emerald-600 dark:text-emerald-500">({metrics.auto.percentage.toFixed(0)}%)</span>
            </div>

            {/* Manual (Azul) - White Pill with Blue Accent */}
            <div className="flex items-center gap-1.5 px-3 py-1 rounded-md bg-white dark:bg-blue-900/20 border border-blue-200/60 dark:border-blue-800 whitespace-nowrap shadow-sm">
                <div className="w-1.5 h-1.5 rounded-full bg-blue-500"></div>
                <span className="text-blue-700 dark:text-blue-400">Manual: {metrics.manual.quantity}</span>
                <span className="font-mono font-bold text-blue-600 dark:text-blue-500">({metrics.manual.percentage.toFixed(0)}%)</span>
            </div>

            {/* Pendente (Amarelo) - White Pill with Amber Accent */}
            {metrics.pending.quantity > 0 && (
                <div className="flex items-center gap-1.5 px-3 py-1 rounded-md bg-white dark:bg-amber-900/20 border border-amber-200/60 dark:border-amber-800 whitespace-nowrap shadow-sm">
                    <ExclamationTriangleIcon className="w-3 h-3 text-amber-500" />
                    <span className="text-amber-700 dark:text-amber-400 font-bold">Pend: {metrics.pending.quantity}</span>
                    <span className="font-mono font-bold text-amber-600 dark:text-amber-500">({formatCurrency(metrics.pending.value, language)})</span>
                </div>
            )}
        </div>
    );
};

const ReportGroup: React.FC<{
    churchId: string;
    results: MatchResult[];
    reportType: 'income' | 'expenses';
    defaultOpen?: boolean;
}> = ({ churchId, results, reportType, defaultOpen = false }) => {
    const {
        churches,
        updateReportData,
        openDeleteConfirmation,
        searchFilters,
        openBulkManualIdentify,
        loadingAiId,
        openManualIdentify
    } = useContext(AppContext);
    const { t, language } = useTranslation();
    const [searchQuery, setSearchQuery] = useState('');
    const [sortConfig, setSortConfig] = useState<SortConfig | null>({ key: 'transaction.date', direction: 'desc' });

    // Always open in this new layout
    const isCollapsed = false;

    const safeResults = useMemo(() => Array.isArray(results) ? results : [], [results]);

    const processedResults = useMemo(() => {
        let filteredData = [...safeResults];

        if (searchFilters.dateRange.start || searchFilters.dateRange.end) {
            const startDate = searchFilters.dateRange.start ? new Date(searchFilters.dateRange.start).getTime() : null;
            const endDate = searchFilters.dateRange.end ? new Date(searchFilters.dateRange.end).getTime() + 86400000 : null;
            filteredData = filteredData.filter(r => {
                const txDate = parseDate(r.transaction.date)?.getTime();
                if (!txDate) return false;
                if (startDate && txDate < startDate) return false;
                if (endDate && txDate >= endDate) return false;
                return true;
            });
        }

        const { operator, value1, value2 } = searchFilters.valueFilter;
        if (operator !== 'any' && value1 !== null) {
            filteredData = filteredData.filter(r => {
                const amount = Math.abs(r.transaction.amount);
                switch (operator) {
                    case 'exact': return amount === value1;
                    case 'gt': return amount > value1;
                    case 'lt': return amount < value1;
                    case 'between': return value2 !== null && amount >= value1 && amount <= value2;
                    default: return true;
                }
            });
        }

        if (searchFilters.reconciliationStatus !== 'all') {
            switch (searchFilters.reconciliationStatus) {
                case 'confirmed_any':
                    filteredData = filteredData.filter(r => r.status === 'IDENTIFICADO');
                    break;
                case 'unconfirmed':
                    filteredData = filteredData.filter(r => r.status === 'NÃO IDENTIFICADO');
                    break;
                case 'confirmed_auto':
                    filteredData = filteredData.filter(r => r.status === 'IDENTIFICADO' && (r.matchMethod === 'AUTOMATIC' || r.matchMethod === 'LEARNED' || !r.matchMethod));
                    break;
                case 'confirmed_manual':
                    filteredData = filteredData.filter(r => r.status === 'IDENTIFICADO' && (r.matchMethod === 'MANUAL' || r.matchMethod === 'AI'));
                    break;
            }
        }

        if (searchFilters.filterBy === 'church' && searchFilters.churchIds.length > 0) {
            filteredData = filteredData.filter(r => searchFilters.churchIds.includes(r.church.id));
        }

        if (searchFilters.filterBy === 'contributor' && searchFilters.contributorName.trim()) {
             filteredData = filteredData.filter(r => filterByUniversalQuery(r, searchFilters.contributorName));
        }

        if (searchQuery.trim()) {
            filteredData = filteredData.filter(r => filterByUniversalQuery(r, searchQuery));
        }

        if (sortConfig !== null) {
            filteredData.sort((a, b) => {
                // ORDENAÇÃO ESPECIAL: PENDENTES COM SUGESTÃO PRIMEIRO
                if (sortConfig.key === 'hasSuggestion') {
                    const valA = a.suggestion ? 1 : 0;
                    const valB = b.suggestion ? 1 : 0;
                    // Desc: Mostra os que TEM sugestão primeiro (1 > 0)
                    return sortConfig.direction === 'desc' ? valB - valA : valA - valB;
                }

                const aValue = getNestedValue(a, sortConfig.key);
                const bValue = getNestedValue(b, sortConfig.key);
                if (sortConfig.key === 'date' || (sortConfig.key.includes('date'))) {
                    const dateA = parseDate(aValue)?.getTime() || 0;
                    const dateB = parseDate(bValue)?.getTime() || 0;
                    return sortConfig.direction === 'asc' ? dateA - dateB : dateB - dateA;
                }
                if (aValue === null || aValue === undefined) return 1;
                if (bValue === null || bValue === undefined) return -1;
                if (typeof aValue === 'number' && typeof bValue === 'number') {
                     return sortConfig.direction === 'asc' ? aValue - bValue : bValue - aValue;
                }
                if (typeof aValue === 'string' && typeof bValue === 'string') {
                    return sortConfig.direction === 'asc' ? aValue.localeCompare(bValue) : bValue.localeCompare(aValue);
                }
                return 0;
            });
        }
        return filteredData;
    }, [safeResults, searchQuery, sortConfig, searchFilters]);

    const handleSort = (key: string) => {
        let direction: SortDirection = 'asc';
        if (sortConfig && sortConfig.key === key && sortConfig.direction === 'asc') {
            direction = 'desc';
        }
        setSortConfig({ key, direction });
    };

    const isUnidentifiedIncome = reportType === 'income' && churchId === 'unidentified';

    const summaryMetrics = useMemo(() => {
        if (reportType === 'expenses') return null;

        const identifiedRows = processedResults.filter(r => r.status === 'IDENTIFICADO');
        const autoConfirmed = identifiedRows.filter(r => r.matchMethod === 'AUTOMATIC' || r.matchMethod === 'LEARNED' || !r.matchMethod);
        const manualConfirmed = identifiedRows.filter(r => r.matchMethod === 'MANUAL' || r.matchMethod === 'AI');
        const bankPendingRows = processedResults.filter(r => r.status === 'NÃO IDENTIFICADO');
        const listPendingRows = processedResults.filter(r => r.status === 'PENDENTE');
        const totalCount = processedResults.length;

        const getRowValue = (r: MatchResult) => {
            if (Math.abs(r.transaction.amount) > 0) return r.transaction.amount;
            return r.contributorAmount || 0;
        };

        const valAuto = autoConfirmed.reduce((sum, r) => sum + getRowValue(r), 0);
        const valManual = manualConfirmed.reduce((sum, r) => sum + getRowValue(r), 0);
        const valBankPending = bankPendingRows.reduce((sum, r) => sum + r.transaction.amount, 0);
        const valListPending = listPendingRows.reduce((sum, r) => sum + (r.contributorAmount || 0), 0);
        const totalPendingValue = valBankPending + valListPending;
        const totalValue = valAuto + valManual + totalPendingValue;
        const totalPendingCount = bankPendingRows.length + listPendingRows.length;

        return {
            auto: { quantity: autoConfirmed.length, value: valAuto, percentage: totalCount > 0 ? (autoConfirmed.length / totalCount) * 100 : 0 },
            manual: { quantity: manualConfirmed.length, value: valManual, percentage: totalCount > 0 ? (manualConfirmed.length / totalCount) * 100 : 0 },
            pending: { quantity: totalPendingCount, value: totalPendingValue, percentage: totalCount > 0 ? (totalPendingCount / totalCount) * 100 : 0 },
            total: { quantity: totalCount, value: totalValue, percentage: 100 }
        };
    }, [processedResults, reportType]);

    const simpleTotalValue = summaryMetrics ? summaryMetrics.total.value : processedResults.reduce((sum, r) => {
         if (reportType === 'income') {
             return sum + (Math.abs(r.transaction.amount) > 0 ? r.transaction.amount : (r.contributorAmount || 0));
         }
         return sum + r.transaction.amount;
    }, 0);

    const getGroupName = (id: string): string => {
        if (id === 'unidentified') return t('reports.unidentifiedGroupTitle');
        if (id === 'all_expenses_group') return t('reports.expenseReportTitle');
        return churches.find(c => c.id === id)?.name || t('reports.unknownChurch');
    };

    const groupName = getGroupName(churchId);

    const handleBulkIdentify = () => {
        const transactions = processedResults.filter(r => r.status !== 'PENDENTE').map(r => r.transaction);
        openBulkManualIdentify(transactions);
    };

    const handleDownload = (format: 'xlsx') => {
        const wb = XLSX.utils.book_new();
        const wsData: any[][] = [
            [groupName],
            [`Gerado em: ${new Date().toLocaleString(language)}`],
            [`Registros: ${processedResults.length}`],
            [''],
            ['Data', reportType === 'income' ? 'Nome / Contribuinte' : 'Descrição', 'Tipo', 'Valor']
        ];

        processedResults.forEach(r => {
            const isPendingList = r.status === 'PENDENTE';
            const amount = isPendingList ? 0 : (reportType === 'income' ? (r.contributorAmount ?? r.transaction.amount) : r.transaction.amount);
            const mainName = reportType === 'income' ? (r.contributor?.cleanedName || r.contributor?.name || '---') : (r.transaction.cleanedDescription || r.transaction.description);
            const type = r.contributor?.contributionType || r.contributionType || r.transaction.contributionType || '---';

            wsData.push([formatDate(r.transaction.date), isPendingList ? `${mainName} (Não Localizado)` : mainName, type, amount]);
        });

        const ws = XLSX.utils.aoa_to_sheet(wsData);
        ws['!cols'] = [{ wch: 12 }, { wch: 40 }, { wch: 15 }, { wch: 15 }];
        XLSX.utils.book_append_sheet(wb, ws, "Relatório");
        XLSX.writeFile(wb, `${groupName.replace(/[^a-z0-9]/gi, '_')}_${reportType}.xlsx`);
    };

    const handlePrint = () => {
        const printWindow = window.open('', '_blank');
        if (!printWindow) return;

        const currentChurch = churches.find(c => c.id === churchId);
        const logoHtml = currentChurch?.logoUrl
            ? `<img src="${currentChurch.logoUrl}" style="max-height: 60px; max-width: 100px; object-fit: contain; margin-right: 15px;" />`
            : '';

        const tableRows = processedResults.map(r => {
            const isPendingList = r.status === 'PENDENTE';
            const amount = isPendingList ? 0 : (reportType === 'income' ? (r.contributorAmount ?? r.transaction.amount) : r.transaction.amount);
            const mainName = reportType === 'income' ? (r.contributor?.cleanedName || r.contributor?.name || '---') : (r.transaction.cleanedDescription || r.transaction.description);
            const type = r.contributor?.contributionType || r.contributionType || r.transaction.contributionType || '---';
            const formattedAmount = isPendingList ? `<span style="text-decoration: line-through; color: #94a3b8;">${formatCurrency(0, language)}</span>` : formatCurrency(amount, language);

            return `<tr><td style="font-family: monospace;">${formatDate(r.transaction.date)}</td><td>${mainName} ${isPendingList ? '<span style="font-size: 9px; color: red; font-style: italic;">(Não Localizado)</span>' : ''}</td><td>${type}</td><td style="text-align:right; font-family: monospace; font-weight: bold;">${formattedAmount}</td></tr>`;
        }).join('');

        let summaryHtml = '';
        if (summaryMetrics) {
            summaryHtml = `<div class="stats-grid"><div class="stat-box" style="border-color: #e2e8f0;"><div class="stat-title" style="color: #64748b;">Total</div><div class="stat-value" style="color: #0f172a;">${summaryMetrics.total.quantity}</div><div class="stat-amount" style="color: #334155;">${formatCurrency(summaryMetrics.total.value, language)}</div></div><div class="stat-box" style="border-color: #bbf7d0; background-color: #f0fdf4;"><div class="stat-title" style="color: #15803d;">Automático</div><div class="stat-value" style="color: #14532d;">${summaryMetrics.auto.quantity}</div><div class="stat-amount" style="color: #166534;">${formatCurrency(summaryMetrics.auto.value, language)}</div></div><div class="stat-box" style="border-color: #bfdbfe; background-color: #eff6ff;"><div class="stat-title" style="color: #1d4ed8;">Manual</div><div class="stat-value" style="color: #1e3a8a;">${summaryMetrics.manual.quantity}</div><div class="stat-amount" style="color: #1e40af;">${formatCurrency(summaryMetrics.manual.value, language)}</div></div><div class="stat-box" style="border-color: #fde68a; background-color: #fffbeb;"><div class="stat-title" style="color: #b45309;">Pendente</div><div class="stat-value" style="color: #78350f;">${summaryMetrics.pending.quantity}</div><div class="stat-amount" style="color: #92400e;">${formatCurrency(summaryMetrics.pending.value, language)}</div></div></div>`;
        } else {
            summaryHtml = `<div class="summary"><div class="summary-item"><span class="label">Total de Registros</span><span class="value">${processedResults.length}</span></div><div class="summary-item"><span class="label">Valor Total Acumulado</span><span class="value">${formatCurrency(simpleTotalValue, language)}</span></div></div>`;
        }

        printWindow.document.write(`<html><head><title>${groupName}</title><style>body { font-family: 'Inter', sans-serif; padding: 40px; color: #1e293b; } .header { border-bottom: 3px solid #0052cc; padding-bottom: 15px; margin-bottom: 30px; display: flex; align-items: center; justify-content: space-between; } .header-left { display: flex; align-items: center; } .header h1 { margin: 0; font-size: 24px; font-weight: 800; text-transform: uppercase; letter-spacing: -0.5px; } .header .meta { text-align: right; font-size: 10px; color: #64748b; font-weight: 600; } table { width: 100%; border-collapse: collapse; margin-top: 10px; } th { background-color: #f8fafc; border-bottom: 2px solid #e2e8f0; padding: 12px 10px; text-align: left; font-size: 10px; font-weight: 800; color: #475569; text-transform: uppercase; letter-spacing: 1px; } td { padding: 12px 10px; border-bottom: 1px solid #f1f5f9; font-size: 12px; } .summary { margin-top: 30px; padding: 20px; background: #f8fafc; border-radius: 12px; display: flex; gap: 40px; } .summary-item { display: flex; flex-direction: column; } .summary-item .label { font-size: 9px; font-weight: 800; color: #64748b; text-transform: uppercase; margin-bottom: 4px; } .summary-item .value { font-size: 16px; font-weight: 800; color: #0f172a; } .stats-grid { display: flex; gap: 15px; margin-bottom: 20px; margin-top: 20px; } .stat-box { flex: 1; padding: 12px; border-radius: 8px; border: 1px solid #e2e8f0; } .stat-title { font-size: 9px; font-weight: 800; text-transform: uppercase; margin-bottom: 4px; letter-spacing: 0.5px; } .stat-value { font-size: 18px; font-weight: 800; line-height: 1; margin-bottom: 4px; } .stat-amount { font-size: 11px; font-weight: 600; font-family: monospace; } @media print { body { padding: 0; } @page { margin: 1.5cm; } }</style></head><body><div class="header"><div class="header-left">${logoHtml}<div><h1>${groupName}</h1><div style="font-size: 12px; font-weight: 600; color: #0052cc; margin-top: 4px;">Relatório de Conciliação Bancária</div></div></div><div class="meta">Gerado em: ${new Date().toLocaleString(language)}<br>Registros: ${processedResults.length}</div></div>${summaryHtml}<table><thead><tr><th style="width: 15%;">Data</th><th style="width: 45%;">${reportType === 'income' ? 'Nome / Contribuinte' : 'Descrição'}</th><th style="width: 20%;">Tipo</th><th style="text-align:right; width: 20%;">Valor</th></tr></thead><tbody>${tableRows}</tbody></table><div style="margin-top: 80px; display: flex; justify-content: space-around;"><div style="text-align: center;"><div style="width: 200px; border-top: 1px solid #000; margin-bottom: 8px;"></div><div style="font-size: 10px; font-weight: 700; text-transform: uppercase;">Tesouraria</div></div><div style="text-align: center;"><div style="width: 200px; border-top: 1px solid #000; margin-bottom: 8px;"></div><div style="font-size: 10px; font-weight: 700; text-transform: uppercase;">Responsável</div></div></div><script>window.onload = () => { setTimeout(() => { window.print(); window.close(); }, 500); };</script></body></html>`);
        printWindow.document.close();
    };

    const handleCustomEdit = useCallback((row: MatchResult) => {
        openManualIdentify(row.transaction.id);
    }, [openManualIdentify]);

    return (
        <div className="flex flex-col h-full overflow-hidden bg-white dark:bg-slate-800 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-700" data-group-id={churchId}>
            {/* Header - Alterado para Azul Médio (Blue-100/Blue-200) para contraste */}
            <div className="flex-shrink-0 px-4 py-2 border-b border-blue-200 dark:border-slate-700 flex items-center justify-between gap-4 bg-[#DBEAFE]/80 dark:bg-slate-900 z-10 backdrop-blur-sm">
                {/* Lado Esquerdo: Identificação em Massa e Métricas */}
                <div className="flex items-center gap-4 flex-1 min-w-0 overflow-hidden">
                    {isUnidentifiedIncome && processedResults.length > 0 && (
                        <button onClick={handleBulkIdentify} className="flex items-center gap-1.5 px-3 py-1 bg-brand-blue hover:bg-blue-600 text-white rounded-full text-[10px] font-bold uppercase tracking-wide shadow-sm hover:-translate-y-0.5 transition-all whitespace-nowrap">
                            <CheckBadgeIcon className="w-3.5 h-3.5" />
                            <span>Resolver ({processedResults.filter(r => r.status !== 'PENDENTE').length})</span>
                        </button>
                    )}

                    {summaryMetrics && <CompactMetricsBar metrics={summaryMetrics} language={language} isExpense={reportType === 'expenses'} />}
                </div>

                {/* Lado Direito: Busca e Ações - Visual Clean */}
                <div className="flex items-center gap-2">
                    <div className="relative w-48 transition-all focus-within:w-64">
                        <SearchIcon className="h-3.5 w-3.5 text-slate-400 absolute left-3 top-1/2 -translate-y-1/2" />
                        <input 
                            type="text" 
                            className="block w-full pl-9 pr-7 py-1 bg-white dark:bg-slate-800 border border-blue-200 dark:border-slate-700 rounded-full text-[11px] font-medium text-slate-700 dark:text-slate-200 focus:ring-1 focus:ring-brand-blue focus:border-brand-blue outline-none transition-all placeholder:text-slate-400 shadow-sm" 
                            placeholder={t('common.search')} 
                            value={searchQuery} 
                            onChange={(e) => setSearchQuery(e.target.value)} 
                        />
                        {searchQuery && <button onClick={() => setSearchQuery('')} className="absolute right-2 top-1/2 -translate-y-1/2 text-slate-400 hover:text-slate-600"><XMarkIcon className="h-3 w-3" /></button>}
                    </div>

                    <div className="h-4 w-px bg-blue-300 dark:bg-slate-700 mx-1"></div>

                    <button onClick={() => handleDownload('xlsx')} className="p-1.5 rounded-lg bg-white/50 text-emerald-600 hover:bg-emerald-50 dark:hover:bg-emerald-900/30 dark:text-emerald-400 transition-colors shadow-sm" title="Baixar Excel">
                        <DocumentArrowDownIcon className="w-4 h-4"/>
                    </button>
                    <button onClick={handlePrint} className="p-1.5 rounded-lg bg-white/50 text-blue-600 hover:bg-blue-50 dark:hover:bg-blue-900/30 dark:text-blue-400 transition-colors shadow-sm" title="Imprimir">
                        <PrinterIcon className="w-4 h-4"/>
                    </button>
                    <button onClick={() => openDeleteConfirmation({ type: 'report-group', id: churchId, name: `relatório de ${groupName}`, meta: { reportType }})} className="p-1.5 rounded-lg bg-white/50 text-rose-600 hover:bg-rose-50 dark:hover:bg-rose-900/30 dark:text-rose-400 transition-colors shadow-sm" title="Excluir Grupo">
                        <TrashIcon className="w-4 h-4"/>
                    </button>
                </div>
            </div>

            {/* Tabela (Ocupa o resto do espaço) */}
            <div className="flex-1 min-h-0 overflow-hidden flex flex-col">
                {processedResults.length > 0 ? (
                    <EditableReportTable 
                        data={processedResults} 
                        onRowChange={(updatedRow) => updateReportData(updatedRow, reportType)} 
                        reportType={reportType} 
                        sortConfig={sortConfig} 
                        onSort={handleSort}
                        loadingAiId={loadingAiId} 
                        onEdit={churchId === 'unidentified' ? handleCustomEdit : undefined}
                    />
                ) : (
                    <div className="flex-1 flex flex-col items-center justify-center text-slate-400 bg-slate-50/20 dark:bg-slate-900/10">
                        <SearchIcon className="w-8 h-8 mb-2 opacity-30" />
                        <p className="text-xs font-medium">Nenhum resultado encontrado.</p>
                    </div>
                )}
            </div>
        </div>
    );
};

export const ReportsView: React.FC = () => {
    const { reportPreviewData, openSaveReportModal, matchResults, activeReportId, saveCurrentReportChanges } = useContext(AppContext);
    const { t, language } = useTranslation();
    const { setActiveView } = useUI();
    const [activeTab, setActiveTab] = useState<'churches' | 'unidentified' | 'expenses'>('churches');
    const [selectedChurchId, setSelectedChurchId] = useState<string | null>(null);

    // DRAG AND DROP STATE
    const [churchOrder, setChurchOrder] = usePersistentState<string[]>('report-tab-order', []);
    const [draggedId, setDraggedId] = useState<string | null>(null);

    if (!reportPreviewData) {
        return (
            <div className="flex-1 flex items-center justify-center">
                <EmptyState icon={<ChartBarIcon className="w-12 h-12 text-brand-blue dark:text-blue-400" />} title={t('empty.reports.title')} message={t('empty.reports.message')} action={{ text: t('empty.dashboard.action'), onClick: () => setActiveView('upload') }} />
            </div>
        );
    }

    const { income, expenses } = reportPreviewData;

    const unidentifiedData = (income['unidentified'] || []) as MatchResult[];

    // Sorted Church Groups with Drag & Drop Logic
    const churchGroups = useMemo(() => {
        let groups = Object.entries(income).filter(([key]) => key !== 'unidentified');

        // 1. Default Sort (Alphabetical)
        groups.sort((a, b) => {
            const nameA = (a[1] as MatchResult[])?.[0]?.church?.name || '';
            const nameB = (b[1] as MatchResult[])?.[0]?.church?.name || '';
            return nameA.localeCompare(nameB);
        });

        // 2. Custom Sort Override based on persisted order
        if (churchOrder.length > 0) {
            groups.sort((a, b) => {
                const indexA = churchOrder.indexOf(a[0]);
                const indexB = churchOrder.indexOf(b[0]);

                if (indexA !== -1 && indexB !== -1) return indexA - indexB; // Both in list, preserve order
                if (indexA !== -1) return -1; // A in list, B not -> A first
                if (indexB !== -1) return 1;  // B in list, A not -> B first
                return 0; // Neither in list -> alphabetical wins
            });
        }
        return groups;
    }, [income, churchOrder]);

    const expenseGroups = Object.entries(expenses) as [string, MatchResult[]][];

    // Metrics
    const churchCount = churchGroups.length;
    const unidentifiedCount = unidentifiedData.length;
    const expensesCount = expenseGroups.reduce((acc, curr) => acc + curr[1].length, 0);

    // Initial load logic: Select the first church if available
    useEffect(() => {
        if (activeTab === 'churches' && !selectedChurchId && churchGroups.length > 0) {
            setSelectedChurchId(churchGroups[0][0]);
        }
    }, [activeTab, churchGroups, selectedChurchId]);

    const handleSaveReport = () => {
        openSaveReportModal({
            type: 'global',
            groupName: 'Relatório Geral',
            results: matchResults
        });
    };

    // --- Drag & Drop Handlers ---
    const handleDragStart = (e: React.DragEvent, id: string) => {
        setDraggedId(id);
        e.dataTransfer.setData('text/plain', id);
        e.dataTransfer.effectAllowed = 'move';
        // Optional: Custom Drag Image could be set here
    };

    const handleDragOver = (e: React.DragEvent) => {
        e.preventDefault(); // Necessary to allow dropping
    };

    const handleDrop = (e: React.DragEvent, targetId: string) => {
        e.preventDefault();
        const sourceId = e.dataTransfer.getData('text/plain');
        if (!sourceId || sourceId === targetId) return;

        // Get current visual order IDs
        const currentIds = churchGroups.map(g => g[0]);
        const fromIndex = currentIds.indexOf(sourceId);
        const toIndex = currentIds.indexOf(targetId);

        if (fromIndex === -1 || toIndex === -1) return;

        // Move item in a copy of the ID list
        const newOrder = [...currentIds];
        const [removed] = newOrder.splice(fromIndex, 1);
        newOrder.splice(toIndex, 0, removed);

        // Update persistent state
        setChurchOrder(newOrder);
        setDraggedId(null);
    };

    const TabButton = ({ id, label, icon: Icon, count, colorClass, activeColorClass }: { id: typeof activeTab, label: string, icon: any, count: number, colorClass: string, activeColorClass: string }) => {
        const isActive = activeTab === id;
        return (
            <button
                onClick={() => setActiveTab(id)}
                className={`
                    flex items-center gap-1.5 px-3 py-1.5 rounded-full transition-all duration-200 border text-[10px] font-bold uppercase tracking-wide
                    ${isActive 
                        ? `${activeColorClass} shadow-sm` 
                        : `bg-white dark:bg-slate-800 border-slate-200 dark:border-slate-700 text-slate-500 hover:bg-slate-50 dark:hover:bg-slate-700`
                    }
                `}
            >
                <Icon className={`w-3 h-3 ${isActive ? 'text-current' : 'text-slate-400'}`} />
                <span>{label}</span>
                {count > 0 && (
                    <span className={`ml-1 px-1.5 py-0.5 rounded text-[9px] ${isActive ? 'bg-white/20' : 'bg-slate-100 dark:bg-slate-900 text-slate-600 dark:text-slate-400'}`}>
                        {count}
                    </span>
                )}
            </button>
        );
    };

    return (
        <div className="flex flex-col h-full animate-fade-in gap-2 pb-2">
            {/* Header Ultra Compacto */}
            <div className="flex-shrink-0 flex items-center justify-between px-1 h-10">
                <div className="flex items-center gap-3">
                    <h2 className="text-lg font-black text-brand-deep dark:text-white tracking-tight leading-none">{t('reports.title')}</h2>
                    <div className="h-4 w-px bg-slate-300 dark:bg-slate-600"></div>
                    {/* MAIN TAB NAVIGATION BAR (Inline with Title) */}
                    <div className="flex items-center gap-2">
                        <TabButton 
                            id="churches" 
                            label="Igrejas" 
                            icon={BuildingOfficeIcon} 
                            count={churchCount} 
                            colorClass="text-brand-blue"
                            activeColorClass="bg-gradient-to-r from-blue-600 to-indigo-600 text-white border-transparent shadow-md shadow-blue-500/20"
                        />
                        <TabButton 
                            id="unidentified" 
                            label="Pendentes" 
                            icon={ExclamationTriangleIcon} 
                            count={unidentifiedCount} 
                            colorClass="text-amber-500"
                            activeColorClass="bg-gradient-to-r from-amber-500 to-orange-500 text-white border-transparent shadow-md shadow-amber-500/20"
                        />
                        <TabButton 
                            id="expenses" 
                            label="Saídas" 
                            icon={BanknotesIcon} 
                            count={expensesCount} 
                            colorClass="text-red-500"
                            activeColorClass="bg-gradient-to-r from-red-500 to-rose-600 text-white border-transparent shadow-md shadow-red-500/20"
                        />
                    </div>
                </div>

                <div className="flex items-center gap-2">
                    {/* BOTÃO SALVAR ALTERAÇÕES (SÓ APARECE SE ESTIVER EDITANDO UM RELATÓRIO EXISTENTE) */}
                    {activeReportId && (
                        <button onClick={saveCurrentReportChanges} className="flex items-center gap-1.5 px-4 py-1.5 bg-emerald-50 text-emerald-600 border border-emerald-200 hover:bg-emerald-100 rounded-full font-bold text-[10px] uppercase shadow-sm hover:-translate-y-0.5 transition-all active:scale-95">
                            <FloppyDiskIcon className="w-3 h-3" />
                            <span>Salvar Alterações</span>
                        </button>
                    )}

                    {/* BOTÃO SALVAR NOVO RELATÓRIO */}
                    <button onClick={handleSaveReport} className="flex items-center gap-1.5 px-4 py-1.5 bg-gradient-to-l from-[#051024] to-[#0033AA] hover:from-[#020610] hover:to-[#002288] text-white rounded-full font-bold text-[10px] uppercase shadow-md hover:-translate-y-0.5 transition-all active:scale-95">
                        <FloppyDiskIcon className="w-3 h-3" />
                        <span>{t('reports.saveReport')}</span>
                    </button>
                </div>
            </div>

            {/* SECONDARY NAVIGATION (SUB-TABS) FOR CHURCHES - DRAGGABLE */}
            {activeTab === 'churches' && churchGroups.length > 0 && (
                <div className="flex items-center gap-1.5 overflow-x-auto pb-1 custom-scrollbar border-b border-slate-100 dark:border-slate-800/50 min-h-[28px]">
                    {churchGroups.map(([churchId, results]) => {
                        const resultsArray = results as MatchResult[];
                        const isActive = selectedChurchId === churchId;
                        const churchName = resultsArray[0]?.church?.name || t('reports.unknownChurch');
                        const isDraggingSelf = draggedId === churchId;

                        return (
                            <button
                                key={churchId}
                                onClick={() => setSelectedChurchId(churchId)}
                                draggable="true"
                                onDragStart={(e) => handleDragStart(e, churchId)}
                                onDragOver={handleDragOver}
                                onDrop={(e) => handleDrop(e, churchId)}
                                className={`
                                    flex-shrink-0 flex items-center gap-1.5 px-2.5 py-0.5 rounded-full border transition-all text-[9px] font-bold uppercase cursor-move
                                    active:cursor-grabbing hover:scale-105
                                    ${isActive 
                                        ? 'bg-blue-50 dark:bg-blue-900/20 text-brand-blue dark:text-blue-400 border-brand-blue/30 dark:border-blue-800 shadow-sm' 
                                        : 'bg-white dark:bg-slate-800 text-slate-500 dark:text-slate-400 border-slate-200 dark:border-slate-700 hover:bg-slate-50 dark:hover:bg-slate-700'
                                    }
                                    ${isDraggingSelf ? 'opacity-50 scale-95 border-dashed border-slate-400' : ''}
                                `}
                                title="Arraste para reordenar"
                            >
                                <span className="truncate max-w-[120px]">{churchName}</span>
                                <span className={`px-1 py-0 rounded-full text-[8px] ${isActive ? 'bg-white dark:bg-slate-900 text-brand-blue dark:text-blue-400' : 'bg-slate-100 dark:bg-slate-900 text-slate-400'}`}>
                                    {resultsArray.length}
                                </span>
                            </button>
                        );
                    })}
                </div>
            )}

            <div className="flex-1 min-h-0 overflow-hidden flex flex-col">

                {/* IGREJAS TAB */}
                {activeTab === 'churches' && (
                    <div className="flex-1 min-h-0 flex flex-col animate-fade-in">
                        {churchGroups.length > 0 ? (
                            // Renderiza APENAS o grupo selecionado
                            churchGroups
                                .filter(([id]) => id === selectedChurchId)
                                .map(([churchId, results]) => (
                                    <ReportGroup key={churchId} churchId={churchId} results={results as MatchResult[]} reportType="income" defaultOpen={true} />
                                ))
                        ) : (
                            <div className="flex flex-col items-center justify-center py-20 text-slate-400 bg-white/50 dark:bg-slate-800/30 rounded-2xl border-2 border-dashed border-slate-200 dark:border-slate-700">
                                <BuildingOfficeIcon className="w-12 h-12 mb-3 opacity-20" />
                                <p className="text-sm font-medium">Nenhum relatório de igreja disponível.</p>
                            </div>
                        )}
                    </div>
                )}

                {/* PENDENTES TAB */}
                {activeTab === 'unidentified' && (
                    <div className="flex-1 min-h-0 flex flex-col animate-fade-in">
                        {unidentifiedData.length > 0 ? (
                            <ReportGroup churchId="unidentified" results={unidentifiedData} reportType="income" defaultOpen={true} />
                        ) : (
                            <div className="flex flex-col items-center justify-center py-20 text-emerald-500 bg-emerald-50/30 dark:bg-emerald-900/10 rounded-2xl border-2 border-dashed border-emerald-100 dark:border-emerald-800/30 h-full">
                                <CheckBadgeIcon className="w-12 h-12 mb-3 opacity-50" />
                                <p className="text-sm font-bold">Tudo certo!</p>
                                <p className="text-xs opacity-70">Não há itens pendentes de identificação.</p>
                            </div>
                        )}
                    </div>
                )}

                {/* SAIDAS TAB */}
                {activeTab === 'expenses' && (
                    <div className="flex-1 min-h-0 flex flex-col animate-fade-in">
                        {expenseGroups.length > 0 ? (
                            expenseGroups.map(([groupId, results]) => (
                                <ReportGroup key={groupId} churchId={groupId} results={results} reportType="expenses" defaultOpen={true} />
                            ))
                        ) : (
                            <div className="flex flex-col items-center justify-center py-20 text-slate-400 bg-white/50 dark:bg-slate-800/30 rounded-2xl border-2 border-dashed border-slate-200 dark:border-slate-700 h-full">
                                <BanknotesIcon className="w-12 h-12 mb-3 opacity-20" />
                                <p className="text-sm font-medium">Nenhum relatório de saídas disponível.</p>
                            </div>
                        )}
                    </div>
                )}
            </div>
        </div>
    );
};

import { useState, useCallback, useMemo } from 'react';
import { usePersistentState } from './usePersistentState';
import { 
    Transaction, 
    Contributor, 
    MatchResult, 
    Church, 
    Bank, 
    FileModel, 
    GroupedReportData, 
    ComparisonType,
    ViewType,
    LearnedAssociation
} from '../types';
import { 
    matchTransactions, 
    groupResultsByChurch, 
    PLACEHOLDER_CHURCH,
    normalizeString,
    processFileContent
} from '../services/processingService';
import { User } from '@supabase/supabase-js';

interface UseReconciliationProps {
    user: User | null; // Adicionado User
    churches: Church[];
    banks: Bank[];
    fileModels: FileModel[];
    similarityLevel: number;
    dayTolerance: number;
    customIgnoreKeywords: string[];
    contributionKeywords: string[];
    learnedAssociations: LearnedAssociation[];
    showToast: (msg: string, type?: 'success' | 'error') => void;
    setIsLoading: (loading: boolean) => void;
    setActiveView: (view: ViewType) => void;
}

export const useReconciliation = ({
    user,
    churches,
    banks,
    fileModels,
    similarityLevel,
    dayTolerance,
    customIgnoreKeywords,
    contributionKeywords,
    learnedAssociations,
    showToast,
    setIsLoading,
    setActiveView
}: UseReconciliationProps) => {

    // Cria um sufixo único baseado no ID do usuário para isolar os dados no LocalStorage/IndexedDB
    const userSuffix = user ? `-${user.id}` : '-guest';

    const [bankStatementFile, setBankStatementFile] = usePersistentState<{ 
        bankId: string, 
        content: string, 
        fileName: string, 
        rawFile?: File,
        processedTransactions?: Transaction[]
    } | null>(`identificapix-statement-v7${userSuffix}`, null, true);

    const [contributorFiles, setContributorFiles] = usePersistentState<{ churchId: string; content: string; fileName: string, contributors?: Contributor[] }[]>(`identificapix-contributors-v6${userSuffix}`, [], true);
    const [matchResults, setMatchResults] = usePersistentState<MatchResult[]>(`identificapix-results-v6${userSuffix}`, [], true);
    const [reportPreviewData, setReportPreviewData] = usePersistentState<{ income: GroupedReportData; expenses: GroupedReportData } | null>(`identificapix-report-preview-v6${userSuffix}`, null, true);
    const [hasActiveSession, setHasActiveSession] = usePersistentState<boolean>(`identificapix-has-session-v6${userSuffix}`, false, false);
    // NOVO: Rastreia se estamos editando um relatório já salvo
    const [activeReportId, setActiveReportId] = usePersistentState<string | null>(`identificapix-active-report-id${userSuffix}`, null, false);

    const [comparisonType, setComparisonType] = useState<ComparisonType>('both');

    const [pendingTraining, setPendingTraining] = useState<{ content: string; fileName: string; type: 'statement' | 'contributor'; entityId: string, rawFile?: File } | null>(null);

    // Manual Identification State
    const [manualIdentificationTx, setManualIdentificationTx] = useState<Transaction | null>(null);
    const [bulkIdentificationTxs, setBulkIdentificationTxs] = useState<Transaction[] | null>(null);
    const [manualMatchState, setManualMatchState] = useState<{ record: MatchResult, suggestions: Transaction[] } | null>(null);
    const [divergenceConfirmation, setDivergenceConfirmation] = useState<MatchResult | null>(null);
    const [loadingAiId, setLoadingAiId] = useState<string | null>(null);
    const [aiSuggestion, setAiSuggestion] = useState<{ id: string, name: string } | null>(null);

    // --- LÓGICA DE LIMPEZA UNIFICADA ---
    // Combina palavras ignoradas globais com os Tipos de Contribuição.
    // Isso garante que "Dízimo", "Oferta", etc., sejam removidos da coluna NOME,
    // mas a detecção de TIPO (que ocorre no raw description) continua funcionando.
    const cleaningKeywords = useMemo(() => {
        return Array.from(new Set([...customIgnoreKeywords, ...contributionKeywords]));
    }, [customIgnoreKeywords, contributionKeywords]);

    const handleStatementUpload = useCallback((content: string, fileName: string, bankId: string, rawFile: File) => {
        setIsLoading(true);
        try {
            // ESTRATÉGIA DIRETA: Usa a lista combinada para limpar descrições
            const result = processFileContent(content, fileName, fileModels, cleaningKeywords);
            const transactions = result.transactions;

            if (transactions.length > 0) {
                setBankStatementFile({ 
                    bankId, 
                    content, 
                    fileName, 
                    rawFile,
                    processedTransactions: transactions 
                });
                showToast(`Extrato carregado (${result.method}).`, 'success');
            } else {
                showToast("Formato de arquivo não reconhecido pelo sistema automático. Verifique se é um arquivo suportado.", "error");
            }
        } catch (e: any) {
            console.error(e);
            showToast("Erro ao ler o arquivo: " + e.message, "error");
        } finally {
            setIsLoading(false);
        }
    }, [setBankStatementFile, showToast, setIsLoading, fileModels, cleaningKeywords]);

    const handleContributorsUpload = useCallback((content: string, fileName: string, churchId: string, rawFile?: File) => {
        setIsLoading(true);
        try {
            // ESTRATÉGIA DIRETA: Usa a lista combinada para limpar nomes de contribuintes
            const result = processFileContent(content, fileName, fileModels, cleaningKeywords);
            const transactions = result.transactions;

            const contributors: Contributor[] = transactions.map(t => ({
                name: t.description,
                cleanedName: t.cleanedDescription,
                normalizedName: normalizeString(t.description, cleaningKeywords),
                amount: t.amount,
                date: t.date,
                originalAmount: t.originalAmount,
                contributionType: t.contributionType
            }));

            if (contributors.length > 0) {
                setContributorFiles(prev => {
                    const other = prev.filter(f => f.churchId !== churchId);
                    return [...other, { churchId, content, fileName, contributors }];
                });
                showToast(`Lista carregada (${result.method}).`, 'success');
            } else {
                showToast("Formato de lista não reconhecido. Use CSV ou Excel padronizado.", "error");
            }
        } catch (e: any) {
            showToast("Erro ao ler o arquivo: " + e.message, "error");
        } finally {
            setIsLoading(false);
        }
    }, [cleaningKeywords, setContributorFiles, showToast, setIsLoading, fileModels]);

    const handleTrainingSuccess = useCallback((model: FileModel, processedData: Transaction[]) => {
        if (!pendingTraining) return;

        const { type, entityId, content, fileName, rawFile } = pendingTraining;

        if (type === 'statement') {
            setBankStatementFile({ 
                bankId: entityId, 
                content, 
                fileName, 
                rawFile,
                processedTransactions: processedData 
            });
            showToast("Extrato processado e salvo!", "success");
        } else {
            const contributors: Contributor[] = processedData.map(t => ({
                name: t.description,
                cleanedName: t.cleanedDescription,
                normalizedName: normalizeString(t.description, cleaningKeywords),
                amount: t.amount,
                date: t.date,
                originalAmount: t.originalAmount,
                contributionType: t.contributionType
            }));

            setContributorFiles(prev => {
                const other = prev.filter(f => f.churchId !== entityId);
                return [...other, { churchId: entityId, content, fileName, contributors }];
            });
            showToast("Lista de contribuintes salva!", "success");
        }

        setPendingTraining(null);
    }, [pendingTraining, cleaningKeywords, setBankStatementFile, setContributorFiles, showToast]);

    const openLabManually = useCallback((targetFile?: { content: string, fileName: string, type: 'statement' | 'contributor', id: string, rawFile?: File }) => {
        if (targetFile) {
            setPendingTraining({
                content: targetFile.content,
                fileName: targetFile.fileName,
                type: targetFile.type,
                entityId: targetFile.id,
                rawFile: targetFile.rawFile
            });
        } else if (bankStatementFile) {
            setPendingTraining({
                content: bankStatementFile.content,
                fileName: bankStatementFile.fileName,
                type: 'statement',
                entityId: bankStatementFile.bankId,
                rawFile: bankStatementFile.rawFile
            });
        } else {
            showToast("Carregue um arquivo primeiro.", "error");
        }
    }, [bankStatementFile, showToast]);

    const removeBankStatementFile = useCallback(() => setBankStatementFile(null), [setBankStatementFile]);
    const removeContributorFile = useCallback((churchId: string) => {
        setContributorFiles(prev => prev.filter(f => f.churchId !== churchId));
    }, [setContributorFiles]);

    // Função para limpar tudo e iniciar nova conciliação
    const resetReconciliation = useCallback(() => {
        setBankStatementFile(null);
        setContributorFiles([]);
        setMatchResults([]);
        setReportPreviewData(null);
        setHasActiveSession(false);
        setActiveReportId(null); // Limpa o ID do relatório ativo
        setManualIdentificationTx(null);
        setBulkIdentificationTxs(null);
        setManualMatchState(null);
        setDivergenceConfirmation(null);
        setAiSuggestion(null);
        showToast("Ambiente limpo para nova conciliação.", "success");
    }, [setBankStatementFile, setContributorFiles, setMatchResults, setReportPreviewData, setHasActiveSession, showToast, setActiveReportId]);

    // --- RECONCILIATION ENGINE JIT (Just-In-Time) ---
    const handleCompare = useCallback(async () => {
        if (!bankStatementFile) return;
        setIsLoading(true);

        try {
            // 1. REPROCESSAMENTO AUTOMÁTICO DO EXTRATO
            // Reprocessa para aplicar as configurações mais recentes (modelos e keywords)
            const stmtResult = processFileContent(bankStatementFile.content, bankStatementFile.fileName, fileModels, cleaningKeywords);
            const activeTransactions = stmtResult.transactions;

            if (activeTransactions.length === 0) {
                throw new Error("O extrato não gerou transações válidas. Verifique o arquivo.");
            }

            setBankStatementFile(prev => prev ? { ...prev, processedTransactions: activeTransactions } : null);

            let filteredTransactions = activeTransactions;
            if (comparisonType === 'income') filteredTransactions = activeTransactions.filter(t => t.amount > 0);
            else if (comparisonType === 'expenses') filteredTransactions = activeTransactions.filter(t => t.amount < 0);

            // 2. REPROCESSAMENTO AUTOMÁTICO DAS LISTAS DE CONTRIBUINTES
            const contributorData = contributorFiles.map(cf => {
                const church = churches.find(c => c.id === cf.churchId) || PLACEHOLDER_CHURCH;

                const listResult = processFileContent(cf.content, cf.fileName, fileModels, cleaningKeywords);
                const currentContributors = listResult.transactions.map(t => ({
                    name: t.description,
                    cleanedName: t.cleanedDescription,
                    normalizedName: normalizeString(t.description, cleaningKeywords),
                    amount: t.amount,
                    date: t.date,
                    originalAmount: t.originalAmount,
                    contributionType: t.contributionType
                }));

                return {
                    church,
                    contributors: currentContributors
                };
            });

            // 3. EXECUTAR O MATCHING
            const results = matchTransactions(
                filteredTransactions, 
                contributorData, 
                { similarityThreshold: similarityLevel, dayTolerance }, 
                learnedAssociations, 
                churches, 
                cleaningKeywords // Usa a lista combinada para matching também
            );

            setMatchResults(results);
            setReportPreviewData({
                // CORREÇÃO: Incluir itens PENDENTE (mesmo com valor 0) no relatório de entradas
                income: groupResultsByChurch(results.filter(r => r.transaction.amount > 0 || r.status === 'PENDENTE')),
                expenses: { 'all_expenses_group': results.filter(r => r.transaction.amount < 0) }
            });
            setHasActiveSession(true);

            // CORREÇÃO: NÃO resetar activeReportId aqui. Se o usuário estiver adicionando arquivos
            // a um relatório existente, queremos manter o ID para que ele possa "Salvar Alterações".
            // setActiveReportId(null); 

            setActiveView('reports');
            showToast("Conciliação finalizada!", 'success');

        } catch (e: any) {
            console.error(e);
            showToast(e.message || "Erro ao processar dados.", "error");
        } finally {
            setIsLoading(false);
        }
    }, [bankStatementFile, contributorFiles, churches, similarityLevel, dayTolerance, cleaningKeywords, learnedAssociations, setMatchResults, setReportPreviewData, setHasActiveSession, setActiveView, showToast, setIsLoading, comparisonType, setBankStatementFile, fileModels, setActiveReportId]);

    const updateReportData = useCallback((updatedRow: MatchResult, reportType: 'income' | 'expenses', idToRemove?: string) => {
        // 1. Atualiza lista plana (MatchResults)
        setMatchResults(prev => {
            let next = prev;
            // Se tiver ID para remover (Transação Fantasma Pendente), remove antes
            if (idToRemove) {
                next = next.filter(r => r.transaction.id !== idToRemove);
            }
            return next.map(r => r.transaction.id === updatedRow.transaction.id ? updatedRow : r);
        });

        // 2. Atualiza dados agrupados (ReportPreview)
        setReportPreviewData(prev => {
            if (!prev) return null;
            const newPreview = JSON.parse(JSON.stringify(prev));
            const targetGroup = reportType === 'expenses' ? newPreview.expenses : newPreview.income;

            if (reportType === 'income') {
                // LÓGICA DE ENTRADAS (Income)
                // Remove o item de qualquer grupo onde ele esteja (tanto o ID real quanto o ID fantasma)
                // Isso evita duplicação ao mover de 'unidentified' ou 'pendente' para uma igreja específica
                Object.keys(targetGroup).forEach(key => {
                    targetGroup[key] = targetGroup[key].filter((r: MatchResult) => {
                        const isTarget = r.transaction.id === updatedRow.transaction.id;
                        const isGhost = idToRemove && r.transaction.id === idToRemove;
                        return !isTarget && !isGhost;
                    });
                });

                // Adiciona o item atualizado ao grupo correto
                const currentChurchId = updatedRow.church.id || 'unidentified';
                if (!newPreview.income[currentChurchId]) newPreview.income[currentChurchId] = [];
                newPreview.income[currentChurchId].push(updatedRow);

            } else {
                // LÓGICA DE SAÍDAS (Expenses) - Mantém comportamento padrão de atualização in-place
                Object.keys(targetGroup).forEach(key => {
                    targetGroup[key] = targetGroup[key].map((r: MatchResult) => 
                        r.transaction.id === updatedRow.transaction.id ? updatedRow : r
                    );
                });
            }

            return newPreview;
        });
    }, [setMatchResults, setReportPreviewData]);

    const discardCurrentReport = useCallback(() => {
        setMatchResults([]);
        setReportPreviewData(null);
        setHasActiveSession(false);
        setActiveReportId(null);
        setActiveView('upload');
    }, [setMatchResults, setReportPreviewData, setHasActiveSession, setActiveView, setActiveReportId]);

    const closeManualIdentify = useCallback(() => {
        setManualIdentificationTx(null);
        setBulkIdentificationTxs(null);
    }, []);

    const openManualMatchModal = useCallback((record: MatchResult) => {
        const suggestions = matchResults.map(r => r.transaction); 
        setManualMatchState({ record, suggestions });
    }, [matchResults]);

    const closeManualMatchModal = useCallback(() => setManualMatchState(null), []);

    const confirmManualAssociation = useCallback((selectedTx: Transaction) => {
        if (!manualMatchState) return;
        const { record } = manualMatchState;

        // Se o registro original era PENDENTE, significa que era uma transação fantasma da lista.
        // Precisamos capturar esse ID para removê-lo, pois ele será substituído pela transação real do banco.
        const ghostIdToRemove = record.status === 'PENDENTE' ? record.transaction.id : undefined;

        const updatedResult: MatchResult = {
            ...record,
            transaction: selectedTx,
            status: 'IDENTIFICADO',
            matchMethod: 'MANUAL',
            similarity: 100
        };

        updateReportData(updatedResult, 'income', ghostIdToRemove);
        closeManualMatchModal();
        showToast("Associação manual aplicada.", "success");
    }, [manualMatchState, updateReportData, closeManualMatchModal, showToast]);

    const openDivergenceModal = useCallback((match: MatchResult) => setDivergenceConfirmation(match), []);
    const closeDivergenceModal = useCallback(() => setDivergenceConfirmation(null), []);

    const confirmDivergence = useCallback((divergentMatch: MatchResult) => {
        updateReportData({ ...divergentMatch, status: 'IDENTIFICADO' }, 'income');
        setDivergenceConfirmation(null);
    }, [updateReportData]);

    const rejectDivergence = useCallback((divergentMatch: MatchResult) => {
        if (divergentMatch.divergence?.expectedChurch) {
             const restored: MatchResult = {
                 ...divergentMatch,
                 church: divergentMatch.divergence.expectedChurch,
                 status: 'IDENTIFICADO'
             };
             updateReportData(restored, 'income');
        } else {
             updateReportData({ ...divergentMatch, status: 'NÃO IDENTIFICADO', church: PLACEHOLDER_CHURCH, contributor: null }, 'income');
        }
        setDivergenceConfirmation(null);
    }, [updateReportData]);

    const handleAnalyze = useCallback(async (transactionId: string) => {
        setLoadingAiId(transactionId);
        setTimeout(() => {
            setAiSuggestion({ id: transactionId, name: "Sugestão AI Simulada" });
            setLoadingAiId(null);
        }, 1500);
    }, []);

    return useMemo(() => ({
        bankStatementFile, contributorFiles, matchResults, setMatchResults, reportPreviewData, setReportPreviewData, hasActiveSession, setHasActiveSession,
        activeReportId, setActiveReportId, // EXPORTED
        pendingTraining, setPendingTraining, comparisonType, setComparisonType,
        handleStatementUpload, handleContributorsUpload, removeBankStatementFile, removeContributorFile,
        handleCompare, updateReportData, discardCurrentReport, openLabManually,
        handleTrainingSuccess, resetReconciliation,
        manualIdentificationTx, setManualIdentificationTx,
        bulkIdentificationTxs, setBulkIdentificationTxs,
        closeManualIdentify,
        manualMatchState, setManualMatchState,
        openManualMatchModal, closeManualMatchModal, confirmManualAssociation,
        divergenceConfirmation, setDivergenceConfirmation,
        openDivergenceModal, closeDivergenceModal, confirmDivergence, rejectDivergence,
        loadingAiId, setLoadingAiId, aiSuggestion, setAiSuggestion, handleAnalyze
    }), [
        bankStatementFile, contributorFiles, matchResults, reportPreviewData, hasActiveSession, activeReportId, pendingTraining, comparisonType, 
        handleStatementUpload, handleContributorsUpload, removeBankStatementFile, removeContributorFile, handleCompare, updateReportData, discardCurrentReport, openLabManually, handleTrainingSuccess,
        setMatchResults, setReportPreviewData, setHasActiveSession, setActiveReportId, resetReconciliation,
        manualIdentificationTx, bulkIdentificationTxs, closeManualIdentify,
        manualMatchState, openManualMatchModal, closeManualMatchModal, confirmManualAssociation,
        divergenceConfirmation, openDivergenceModal, closeDivergenceModal, confirmDivergence, rejectDivergence,
        loadingAiId, aiSuggestion, handleAnalyze
    ]);
};

import React, { createContext, useState, useMemo, useCallback, useEffect, useRef } from 'react';
import { useAuth } from './AuthContext';
import { useUI } from './UIContext';
import { useReferenceData } from '../hooks/useReferenceData';
import { useReconciliation } from '../hooks/useReconciliation';
import { useReportManager } from '../hooks/useReportManager';
import { usePersistentState } from '../hooks/usePersistentState';
import {
    Transaction, Contributor, MatchResult, Bank, Church, ChurchFormData,
    DeletingItem, ComparisonType, GroupedReportData, SearchFilters, SavedReport,
    SavingReportState, LearnedAssociation, MatchMethod, FileModel
} from '../types';
import { groupResultsByChurch, PLACEHOLDER_CHURCH } from '../services/processingService';

import { supabase } from '../services/supabaseClient';
import { useTranslation } from './I18nContext';
import { LoadingSpinner } from '../components/shared/LoadingSpinner';
import { RecompareModal } from '../components/modals/RecompareModal';

interface AppContextType {
    // Data State (from useReferenceData)
    banks: Bank[];
    churches: Church[];
    fileModels: FileModel[];
    fetchModels: () => Promise<void>;
    setBanks: React.Dispatch<React.SetStateAction<Bank[]>>;
    setChurches: React.Dispatch<React.SetStateAction<Church[]>>;
    similarityLevel: number;
    setSimilarityLevel: React.Dispatch<React.SetStateAction<number>>;
    dayTolerance: number;
    setDayTolerance: React.Dispatch<React.SetStateAction<number>>;
    customIgnoreKeywords: string[]; 
    effectiveIgnoreKeywords: string[]; 
    addIgnoreKeyword: (keyword: string) => void;
    removeIgnoreKeyword: (keyword: string) => void;
    contributionKeywords: string[];
    addContributionKeyword: (keyword: string) => void;
    removeContributionKeyword: (keyword: string) => void;
    learnedAssociations: LearnedAssociation[];

    // Edit States
    editingBank: Bank | null;
    editingChurch: Church | null;
    openEditBank: (bank: Bank) => void;
    closeEditBank: () => void;
    updateBank: (bankId: string, name: string) => void;
    addBank: (name: string) => Promise<boolean>;
    openEditChurch: (church: Church) => void;
    closeEditChurch: () => void;
    updateChurch: (churchId: string, data: ChurchFormData) => void;
    addChurch: (data: ChurchFormData) => Promise<boolean>;

    // Reconciliation State (from useReconciliation)
    bankStatementFile: { bankId: string, content: string, fileName: string, rawFile?: File } | null;
    contributorFiles: { churchId: string; content: string; fileName: string; contributors?: Contributor[] }[];
    matchResults: MatchResult[];
    setMatchResults: React.Dispatch<React.SetStateAction<MatchResult[]>>;
    reportPreviewData: { income: GroupedReportData; expenses: GroupedReportData } | null;
    setReportPreviewData: React.Dispatch<React.SetStateAction<{ income: GroupedReportData; expenses: GroupedReportData } | null>>;
    comparisonType: ComparisonType;
    setComparisonType: React.Dispatch<React.SetStateAction<ComparisonType>>;
    hasActiveSession: boolean;
    isCompareDisabled: boolean;
    pendingTraining: any;
    setPendingTraining: (val: any) => void;
    activeReportId: string | null;

    // Reconciliation Actions
    openLabManually: (targetFile?: { content: string, fileName: string, type: 'statement' | 'contributor', id: string, rawFile?: File }) => void;
    handleStatementUpload: (content: string, fileName: string, bankId: string, rawFile: File) => void;
    handleContributorsUpload: (content: string, fileName: string, churchId: string) => void;
    handleTrainingSuccess: (model: FileModel, data: Transaction[]) => void;
    removeBankStatementFile: () => void;
    removeContributorFile: (churchId: string) => void;
    handleCompare: () => void;
    handleBackToSettings: () => void;
    updateReportData: (updatedRow: MatchResult, reportType: 'income' | 'expenses', idToRemove?: string) => void;
    discardCurrentReport: () => void;
    resetReconciliation: () => void; // NOVO

    // Manual Operations State & Handlers
    manualIdentificationTx: Transaction | null;
    setManualIdentificationTx: React.Dispatch<React.SetStateAction<Transaction | null>>;
    bulkIdentificationTxs: Transaction[] | null;
    setBulkIdentificationTxs: React.Dispatch<React.SetStateAction<Transaction[] | null>>;

    openManualIdentify: (transactionId: string) => void;
    openBulkManualIdentify: (transactions: Transaction[]) => void;
    closeManualIdentify: () => void;
    confirmManualIdentification: (transactionId: string, churchId: string) => void;
    confirmBulkManualIdentification: (transactionIds: string[], churchId: string) => void;

    manualMatchState: { record: MatchResult, suggestions: Transaction[] } | null;
    setManualMatchState: React.Dispatch<React.SetStateAction<{ record: MatchResult, suggestions: Transaction[] } | null>>;
    openManualMatchModal: (recordToMatch: MatchResult) => void;
    closeManualMatchModal: () => void;
    confirmManualAssociation: (selectedTx: Transaction) => void;

    // Smart Edit (NEW)
    smartEditTarget: MatchResult | null;
    openSmartEdit: (match: MatchResult) => void;
    closeSmartEdit: () => void;
    saveSmartEdit: (updatedMatch: MatchResult) => void;

    divergenceConfirmation: MatchResult | null;
    setDivergenceConfirmation: React.Dispatch<React.SetStateAction<MatchResult | null>>;
    openDivergenceModal: (match: MatchResult) => void;
    closeDivergenceModal: () => void;
    confirmDivergence: (divergentMatch: MatchResult) => void;
    rejectDivergence: (divergentMatch: MatchResult) => void;

    learnAssociation: (matchResult: MatchResult) => Promise<void>;
    findMatchResult: (transactionId: string) => MatchResult | undefined;

    // AI
    loadingAiId: string | null;
    aiSuggestion: { id: string, name: string } | null;
    handleAnalyze: (transaction: Transaction, candidates: Contributor[]) => void;

    // Recompare Modal
    isRecompareModalOpen: boolean;
    openRecompareModal: () => void;
    closeRecompareModal: () => void;

    // Reports & Search (from useReportManager)
    savedReports: SavedReport[];
    maxSavedReports: number; // NOVO: Limite de relatórios
    searchFilters: SearchFilters;
    setSearchFilters: React.Dispatch<React.SetStateAction<SearchFilters>>;
    isSearchFiltersOpen: boolean;
    openSearchFilters: () => void;
    closeSearchFilters: () => void;
    clearSearchFilters: () => void;
    allHistoricalResults: MatchResult[];

    savingReportState: SavingReportState | null;
    openSaveReportModal: (state: SavingReportState) => void;
    closeSaveReportModal: () => void;
    confirmSaveReport: (name: string) => void;
    viewSavedReport: (reportId: string) => void;
    updateSavedReportName: (reportId: string, newName: string) => void;
    saveFilteredReport: (results: MatchResult[]) => void;
    saveCurrentReportChanges: () => void; // Nova função

    // Global
    deletingItem: DeletingItem | null;
    openDeleteConfirmation: (item: DeletingItem) => void;
    closeDeleteConfirmation: () => void;
    confirmDeletion: () => void;
    initialDataLoaded: boolean;
    isSyncing: boolean; // NOVO: Estado para indicar sincronização em background
    summary: {
        autoConfirmed: { count: number; value: number; };
        manualConfirmed: { count: number; value: number; };
        pending: { count: number; value: number; };
        identifiedCount: number;
        unidentifiedCount: number;
        totalValue: number;
        valuePerChurch: [string, number][];
        isHistorical: boolean;
        methodBreakdown: Record<MatchMethod, number>;
    };
    isPaymentModalOpen: boolean;
    openPaymentModal: () => void;
    closePaymentModal: () => void;
}

export const AppContext = createContext<AppContextType>(null!);

export const AppProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
    const { user, systemSettings, incrementAiUsage } = useAuth();
    const { t } = useTranslation();
    const { showToast, setIsLoading, setActiveView } = useUI();

    const referenceData = useReferenceData(user, showToast);
    const reportManager = useReportManager(user, showToast);

    const effectiveIgnoreKeywords = useMemo(() => {
        return systemSettings.globalIgnoreKeywords || [];
    }, [systemSettings.globalIgnoreKeywords]);

    const reconciliation = useReconciliation({
        user, 
        churches: referenceData.churches,
        banks: referenceData.banks,
        fileModels: [],
        similarityLevel: referenceData.similarityLevel,
        dayTolerance: referenceData.dayTolerance,
        customIgnoreKeywords: effectiveIgnoreKeywords,
        contributionKeywords: referenceData.contributionKeywords,
        learnedAssociations: referenceData.learnedAssociations,
        showToast, setIsLoading, setActiveView
    });

    const [initialDataLoaded, setInitialDataLoaded] = useState(true);
    const [isSyncing, setIsSyncing] = useState(false); // Inicializa sem sync

    const [deletingItem, setDeletingItem] = useState<DeletingItem | null>(null);
    const [isPaymentModalOpen, setIsPaymentModalOpen] = useState(false);
    const [isRecompareModalOpen, setIsRecompareModalOpen] = useState(false);

    const [smartEditTarget, setSmartEditTarget] = useState<MatchResult | null>(null);

    const userSuffix = user ? `-${user.id}` : '-guest';
    const [summary, setSummary] = usePersistentState(`identificapix-dashboard-summary-v6${userSuffix}`, {
        autoConfirmed: { count: 0, value: 0 },
        manualConfirmed: { count: 0, value: 0 },
        pending: { count: 0, value: 0 },
        identifiedCount: 0, unidentifiedCount: 0, totalValue: 0, valuePerChurch: [], isHistorical: false,
        methodBreakdown: { 'AUTOMATIC': 0, 'MANUAL': 0, 'LEARNED': 0, 'AI': 0, 'TEMPLATE': 0 }
    }, false);

    // Fetch de Dados (Background Sync) - NÃO BLOQUEANTE
    useEffect(() => {
        if (!user) return;
        const fetchData = async () => {
            // Usamos isSyncing para dar feedback sutil (ex: na sidebar) se necessário.
            setIsSyncing(true);

            try {
                // OTIMIZAÇÃO CRÍTICA (Resource Exhaustion Fix):
                // NÃO selecionamos a coluna 'data' (JSON pesado) na listagem inicial.
                // Isso evita o erro de "Exhausting multiple resources" no Supabase Nano.
                const [churchesRes, banksRes, reportsRes] = await Promise.all([
                    supabase.from('churches').select('*').order('name'),
                    supabase.from('banks').select('*').order('name'),
                    supabase.from('saved_reports')
                        .select('id, name, created_at, record_count, user_id') // SEM 'data'
                        .eq('user_id', user.id)
                        .order('created_at', { ascending: false }),
                ]);

                if (churchesRes.data) referenceData.setChurches(churchesRes.data as any);
                if (banksRes.data) referenceData.setBanks(banksRes.data as any);

                if (reportsRes.data) {
                    reportManager.setSavedReports((reportsRes.data || []).map(r => ({ 
                        id: r.id, 
                        name: r.name, 
                        createdAt: r.created_at, 
                        recordCount: r.record_count, 
                        user_id: r.user_id, 
                        data: null // Lazy Load: Iniciamos sem dados pesados
                    })));
                }
            } catch (err) { console.error('Background sync failed', err); } 
            finally { 
                setIsSyncing(false); 
                setInitialDataLoaded(true); 
            }
        };
        fetchData();
    }, [user?.id]);

    const resultsHash = JSON.stringify(reconciliation.matchResults.map(r => r.transaction.id + r.status));
    const reportsHash = reportManager.savedReports.length;

    useEffect(() => {
        const timer = setTimeout(() => {
            let resultsToProcess = reconciliation.matchResults;
            let isHistorical = false;
            // No modo Lazy Load, o Dashboard histórico fica limitado aos dados já carregados na memória
            // ou apenas à sessão ativa, para evitar crash.
            if (resultsToProcess.length === 0 && reportManager.savedReports.length > 0) {
                resultsToProcess = reportManager.savedReports.flatMap(report => report.data?.results || []);
                isHistorical = true;
            }
            const autoConfirmed = resultsToProcess.filter(r => r.status === 'IDENTIFICADO' && (r.matchMethod === 'AUTOMATIC' || r.matchMethod === 'LEARNED' || !r.matchMethod));
            const manualConfirmed = resultsToProcess.filter(r => r.status === 'IDENTIFICADO' && (r.matchMethod === 'MANUAL' || r.matchMethod === 'AI'));
            const pending = resultsToProcess.filter(r => r.status === 'NÃO IDENTIFICADO');
            const valuePerChurch = new Map<string, number>();
            const methodBreakdown: Record<MatchMethod, number> = { 'AUTOMATIC': 0, 'MANUAL': 0, 'LEARNED': 0, 'AI': 0, 'TEMPLATE': 0 };
            resultsToProcess.forEach(r => {
                if (r.status === 'IDENTIFICADO') {
                    if (r.church && r.church.name !== '---' && r.transaction.amount > 0) {
                        const current = valuePerChurch.get(r.church.name) || 0;
                        valuePerChurch.set(r.church.name, current + r.transaction.amount);
                    }
                    const method = r.matchMethod || 'AUTOMATIC';
                    if (methodBreakdown[method] !== undefined) methodBreakdown[method]++;
                }
            });
            const newTotal = resultsToProcess.reduce((sum, r) => sum + r.transaction.amount, 0);
            setSummary(prev => ({
                autoConfirmed: { count: autoConfirmed.length, value: autoConfirmed.reduce((sum, r) => sum + r.transaction.amount, 0) },
                manualConfirmed: { count: manualConfirmed.length, value: manualConfirmed.reduce((sum, r) => sum + r.transaction.amount, 0) },
                pending: { count: pending.length, value: pending.reduce((sum, r) => sum + r.transaction.amount, 0) },
                identifiedCount: autoConfirmed.length + manualConfirmed.length,
                unidentifiedCount: pending.length, totalValue: newTotal,
                valuePerChurch: Array.from(valuePerChurch.entries()).sort((a, b) => b[1] - a[1]),
                isHistorical, methodBreakdown
            }));
        }, 300);
        return () => clearTimeout(timer);
    }, [resultsHash, reportsHash]);

    const handleBackToSettings = useCallback(() => setActiveView('upload'), [setActiveView]);
    const openDeleteConfirmation = useCallback((item: DeletingItem) => setDeletingItem(item), []);
    const closeDeleteConfirmation = useCallback(() => setDeletingItem(null), []);
    const confirmDeletion = useCallback(async () => {
        if (!deletingItem) return;
        if (deletingItem.type === 'report-row') {
             reconciliation.setReportPreviewData(prev => {
                 if (!prev) return null;
                 const newPreview = { ...prev };
                 const targetGroup = deletingItem.meta?.reportType === 'expenses' ? newPreview.expenses : newPreview.income;
                 Object.keys(targetGroup).forEach(key => { targetGroup[key] = targetGroup[key].filter(r => r.transaction.id !== deletingItem.id); });
                 return newPreview;
             });
             reconciliation.setMatchResults(prev => prev.filter(r => r.transaction.id !== deletingItem.id));
        } else if (deletingItem.type === 'report-group') {
             reconciliation.setReportPreviewData(prev => {
                 if (!prev) return null;
                 const newPreview = { ...prev };
                 const targetGroup = deletingItem.meta?.reportType === 'expenses' ? newPreview.expenses : newPreview.income;
                 if (targetGroup[deletingItem.id]) {
                     const idsToRemove = targetGroup[deletingItem.id].map(r => r.transaction.id);
                     delete targetGroup[deletingItem.id];
                     reconciliation.setMatchResults(prev => prev.filter(r => !idsToRemove.includes(r.transaction.id)));
                 }
                 return newPreview;
             });
        } else if (deletingItem.type === 'bank') {
            referenceData.setBanks(prev => prev.filter(b => b.id !== deletingItem.id));
            await supabase.from('banks').delete().eq('id', deletingItem.id);
        } else if (deletingItem.type === 'church') {
            referenceData.setChurches(prev => prev.filter(c => c.id !== deletingItem.id));
            await supabase.from('churches').delete().eq('id', deletingItem.id);
        } else if (deletingItem.type === 'report-saved') {
            reportManager.setSavedReports(prev => prev.filter(r => r.id !== deletingItem.id));
            await supabase.from('saved_reports').delete().eq('id', deletingItem.id);
        } else if (deletingItem.type === 'uploaded-files') { reconciliation.removeBankStatementFile(); }
        closeDeleteConfirmation();
        showToast("Ação realizada com sucesso.");
    }, [deletingItem, user, referenceData, reportManager, reconciliation, showToast, closeDeleteConfirmation]);

    const viewSavedReport = useCallback(async (reportId: string) => {
        setIsLoading(true);
        try {
            let report = reportManager.savedReports.find(r => r.id === reportId);
            if (!report) return;

            // LAZY LOAD LOGIC: Busca o conteúdo 'data' apenas se ele estiver vazio
            if (!report.data) {
                const { data: reportContent, error } = await supabase
                    .from('saved_reports')
                    .select('data')
                    .eq('id', reportId)
                    .single();

                if (error) throw error;

                if (reportContent) {
                    const parsedData = typeof reportContent.data === 'string' 
                        ? JSON.parse(reportContent.data) 
                        : reportContent.data;

                    report = { ...report, data: parsedData };
                    // Atualiza cache local
                    reportManager.setSavedReports(prev => prev.map(r => r.id === reportId ? report! : r));
                }
            }

            if (!report.data) throw new Error("Conteúdo do relatório vazio.");

            const validResults = report.data.results.map((r: any) => ({ ...r, church: r.church || PLACEHOLDER_CHURCH }));
            reconciliation.setMatchResults(validResults);
            reconciliation.setReportPreviewData({
                income: groupResultsByChurch(validResults.filter((r: any) => r.transaction.amount > 0 || r.status === 'PENDENTE')),
                expenses: { 'all_expenses_group': validResults.filter((r: any) => r.transaction.amount < 0) }
            });
            reconciliation.setHasActiveSession(true); 
            reconciliation.setActiveReportId(reportId); // CRÍTICO: Define qual relatório está sendo editado
            setActiveView('reports'); 
        } catch (error: any) {
            console.error(error);
            showToast("Erro ao abrir relatório: " + error.message, "error");
        } finally {
            setIsLoading(false);
        }
    }, [reportManager.savedReports, reconciliation, setActiveView, setIsLoading, showToast]);

    // Nova função para salvar as alterações do relatório ativo
    const saveCurrentReportChanges = useCallback(() => {
        const reportId = reconciliation.activeReportId;
        if (!reportId) {
            showToast("Nenhum relatório salvo ativo para atualizar.", "error");
            return;
        }
        reportManager.overwriteSavedReport(reportId, reconciliation.matchResults);
    }, [reconciliation.activeReportId, reconciliation.matchResults, reportManager, showToast]);

    const findMatchResult = useCallback((transactionId: string) => reconciliation.matchResults.find(r => r.transaction.id === transactionId) || reportManager.allHistoricalResults.find(r => r.transaction.id === transactionId), [reconciliation.matchResults, reportManager.allHistoricalResults]);

    const openManualIdentify = useCallback((transactionId: string) => {
        const result = findMatchResult(transactionId);
        if (result) reconciliation.setManualIdentificationTx(result.transaction);
    }, [findMatchResult, reconciliation]);

    const openBulkManualIdentify = useCallback((transactions: Transaction[]) => { reconciliation.setBulkIdentificationTxs(transactions); }, [reconciliation]);

    const confirmManualIdentification = useCallback((transactionId: string, churchId: string) => {
        const church = referenceData.churches.find(c => c.id === churchId);
        const result = findMatchResult(transactionId);
        if (church && result) {
            const updated: MatchResult = { ...result, status: 'IDENTIFICADO', church, contributor: { id: `manual-${transactionId}`, name: result.transaction.cleanedDescription || result.transaction.description, amount: result.transaction.amount }, matchMethod: 'MANUAL', similarity: 100, contributorAmount: result.transaction.amount };
            if (reconciliation.matchResults.some(r => r.transaction.id === transactionId)) reconciliation.updateReportData(updated, 'income');
            else reportManager.updateSavedReportTransaction(transactionId, updated);
            reconciliation.closeManualIdentify(); 
            // Feedback modificado para não confundir com salvamento em banco
            showToast('Identificação realizada.', 'success');
        }
    }, [referenceData.churches, findMatchResult, reconciliation, reportManager, showToast]);

    const confirmBulkManualIdentification = useCallback((transactionIds: string[], churchId: string) => {
        const church = referenceData.churches.find(c => c.id === churchId);
        if (!church) return;

        transactionIds.forEach(id => {
            const result = findMatchResult(id);
            if (result) {
                const updated: MatchResult = { 
                    ...result, 
                    status: 'IDENTIFICADO', 
                    church, 
                    contributor: { id: `manual-${id}`, name: result.transaction.cleanedDescription || result.transaction.description, amount: result.transaction.amount }, 
                    matchMethod: 'MANUAL', 
                    similarity: 100, 
                    contributorAmount: result.transaction.amount 
                };
                if (reconciliation.matchResults.some(r => r.transaction.id === id)) reconciliation.updateReportData(updated, 'income');
                else reportManager.updateSavedReportTransaction(id, updated);
            }
        });
        reconciliation.closeManualIdentify();
        showToast(`${transactionIds.length} transações identificadas.`, 'success');
    }, [referenceData.churches, findMatchResult, reconciliation, reportManager, showToast]);

    const openSmartEdit = useCallback((match: MatchResult) => {
        setSmartEditTarget(match);
    }, []);

    const closeSmartEdit = useCallback(() => {
        setSmartEditTarget(null);
        reconciliation.setAiSuggestion(null);
    }, [reconciliation]);

    const saveSmartEdit = useCallback((updatedMatch: MatchResult) => {
        if (reconciliation.matchResults.some(r => r.transaction.id === updatedMatch.transaction.id)) {
            // Se for uma edição de match reverso, precisamos remover o ID fantasma
            const ghostId = smartEditTarget?.status === 'PENDENTE' ? smartEditTarget.transaction.id : undefined;
            reconciliation.updateReportData(updatedMatch, 'income', ghostId);
        } else {
            reportManager.updateSavedReportTransaction(updatedMatch.transaction.id, updatedMatch);
        }
        // Feedback modificado para não confundir com salvamento em banco
        showToast("Edição aplicada na tabela.", "success");
        setSmartEditTarget(null);
        reconciliation.setAiSuggestion(null);
    }, [reconciliation, reportManager, showToast, smartEditTarget]);

    const handleAnalyze = useCallback(async (transaction: Transaction, candidates: Contributor[]) => {
        reconciliation.setLoadingAiId(transaction.id);
        try {
            const candidateNames = candidates.slice(0, 50).map(c => c.name);
            const response = await fetch('/api/ai/suggestion', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    transactionDescription: transaction.description,
                    contributorNames: candidateNames
                })
            });

            if (!response.ok) throw new Error('Falha na API de IA');
            const data = await response.json();
            const suggestionText = data.text;

            if (suggestionText && !suggestionText.includes("Nenhuma sugestão clara")) {
                reconciliation.setAiSuggestion({ id: transaction.id, name: suggestionText });
                incrementAiUsage(); 
            } else {
                reconciliation.setAiSuggestion(null);
            }
        } catch (error) {
            console.error("Erro na análise IA:", error);
            showToast("Não foi possível obter sugestão da IA.", "error");
        } finally {
            reconciliation.setLoadingAiId(null);
        }
    }, [incrementAiUsage, showToast, reconciliation]);

    const value = useMemo(() => ({
        ...referenceData, ...reconciliation, isCompareDisabled: !reconciliation.bankStatementFile,
        effectiveIgnoreKeywords, 
        openManualIdentify, openBulkManualIdentify, confirmManualIdentification, confirmBulkManualIdentification, findMatchResult,
        ...reportManager, viewSavedReport, handleBackToSettings, deletingItem, openDeleteConfirmation,
        closeDeleteConfirmation, confirmDeletion, initialDataLoaded, isSyncing, summary, isPaymentModalOpen,
        openPaymentModal: () => setIsPaymentModalOpen(true), closePaymentModal: () => setIsPaymentModalOpen(false),
        isRecompareModalOpen, openRecompareModal: () => setIsRecompareModalOpen(true), closeRecompareModal: () => setIsRecompareModalOpen(false),
        smartEditTarget, openSmartEdit, closeSmartEdit, saveSmartEdit, handleAnalyze,
        saveCurrentReportChanges
    }), [referenceData, reconciliation, effectiveIgnoreKeywords, reportManager, viewSavedReport, handleBackToSettings, deletingItem, openDeleteConfirmation, closeDeleteConfirmation, confirmDeletion, initialDataLoaded, isSyncing, summary, isPaymentModalOpen, isRecompareModalOpen, openManualIdentify, openBulkManualIdentify, confirmManualIdentification, confirmBulkManualIdentification, findMatchResult, smartEditTarget, openSmartEdit, closeSmartEdit, saveSmartEdit, handleAnalyze, saveCurrentReportChanges]);

    return <AppContext.Provider value={value}>{children}<RecompareModal /></AppContext.Provider>;
};

import { useState, useCallback, useMemo } from 'react';
import { usePersistentState } from './usePersistentState';
import { 
    Transaction, 
    Contributor, 
    MatchResult, 
    Church, 
    Bank, 
    FileModel, 
    GroupedReportData, 
    ComparisonType, 
    ViewType,
    LearnedAssociation
} from '../types';
import { 
    matchTransactions, 
    groupResultsByChurch, 
    PLACEHOLDER_CHURCH,
    normalizeString,
    processFileContent
} from '../services/processingService';
import { User } from '@supabase/supabase-js';

interface UseReconciliationProps {
    user: User | null; // Adicionado User
    churches: Church[];
    banks: Bank[];
    fileModels: FileModel[];
    similarityLevel: number;
    dayTolerance: number;
    customIgnoreKeywords: string[];
    contributionKeywords: string[];
    learnedAssociations: LearnedAssociation[];
    showToast: (msg: string, type?: 'success' | 'error') => void;
    setIsLoading: (loading: boolean) => void;
    setActiveView: (view: ViewType) => void;
}

export const useReconciliation = ({
    user,
    churches,
    banks,
    fileModels,
    similarityLevel,
    dayTolerance,
    customIgnoreKeywords,
    contributionKeywords,
    learnedAssociations,
    showToast,
    setIsLoading,
    setActiveView
}: UseReconciliationProps) => {

    // Cria um sufixo único baseado no ID do usuário para isolar os dados no LocalStorage/IndexedDB
    const userSuffix = user ? `-${user.id}` : '-guest';

    const [bankStatementFile, setBankStatementFile] = usePersistentState<{ 
        bankId: string, 
        content: string, 
        fileName: string, 
        rawFile?: File,
        processedTransactions?: Transaction[]
    } | null>(`identificapix-statement-v7${userSuffix}`, null, true);

    const [contributorFiles, setContributorFiles] = usePersistentState<{ churchId: string; content: string; fileName: string, contributors?: Contributor[] }[]>(`identificapix-contributors-v6${userSuffix}`, [], true);
    const [matchResults, setMatchResults] = usePersistentState<MatchResult[]>(`identificapix-results-v6${userSuffix}`, [], true);
    const [reportPreviewData, setReportPreviewData] = usePersistentState<{ income: GroupedReportData; expenses: GroupedReportData } | null>(`identificapix-report-preview-v6${userSuffix}`, null, true);
    const [hasActiveSession, setHasActiveSession] = usePersistentState<boolean>(`identificapix-has-session-v6${userSuffix}`, false, false);
    // NOVO: Rastreia se estamos editando um relatório já salvo
    const [activeReportId, setActiveReportId] = usePersistentState<string | null>(`identificapix-active-report-id${userSuffix}`, null, false);

    const [comparisonType, setComparisonType] = useState<ComparisonType>('both');

    const [pendingTraining, setPendingTraining] = useState<{ content: string; fileName: string; type: 'statement' | 'contributor'; entityId: string, rawFile?: File } | null>(null);

    // Manual Identification State
    const [manualIdentificationTx, setManualIdentificationTx] = useState<Transaction | null>(null);
    const [bulkIdentificationTxs, setBulkIdentificationTxs] = useState<Transaction[] | null>(null);
    const [manualMatchState, setManualMatchState] = useState<{ record: MatchResult, suggestions: Transaction[] } | null>(null);
    const [divergenceConfirmation, setDivergenceConfirmation] = useState<MatchResult | null>(null);
    const [loadingAiId, setLoadingAiId] = useState<string | null>(null);
    const [aiSuggestion, setAiSuggestion] = useState<{ id: string, name: string } | null>(null);

    // --- LÓGICA DE LIMPEZA UNIFICADA ---
    // Combina palavras ignoradas globais com os Tipos de Contribuição.
    // Isso garante que "Dízimo", "Oferta", etc., sejam removidos da coluna NOME,
    // mas a detecção de TIPO (que ocorre no raw description) continua funcionando.
    const cleaningKeywords = useMemo(() => {
        return Array.from(new Set([...customIgnoreKeywords, ...contributionKeywords]));
    }, [customIgnoreKeywords, contributionKeywords]);

    const handleStatementUpload = useCallback((content: string, fileName: string, bankId: string, rawFile: File) => {
        setIsLoading(true);
        try {
            // ESTRATÉGIA DIRETA: Usa a lista combinada para limpar descrições
            const result = processFileContent(content, fileName, fileModels, cleaningKeywords);
            const transactions = result.transactions;

            if (transactions.length > 0) {
                setBankStatementFile({ 
                    bankId, 
                    content, 
                    fileName, 
                    rawFile,
                    processedTransactions: transactions 
                });
                showToast(`Extrato carregado (${result.method}).`, 'success');
            } else {
                showToast("Formato de arquivo não reconhecido pelo sistema automático. Verifique se é um arquivo suportado.", "error");
            }
        } catch (e: any) {
            console.error(e);
            showToast("Erro ao ler o arquivo: " + e.message, "error");
        } finally {
            setIsLoading(false);
        }
    }, [setBankStatementFile, showToast, setIsLoading, fileModels, cleaningKeywords]);

    const handleContributorsUpload = useCallback((content: string, fileName: string, churchId: string, rawFile?: File) => {
        setIsLoading(true);
        try {
            // ESTRATÉGIA DIRETA: Usa a lista combinada para limpar nomes de contribuintes
            const result = processFileContent(content, fileName, fileModels, cleaningKeywords);
            const transactions = result.transactions;

            const contributors: Contributor[] = transactions.map(t => ({
                name: t.description,
                cleanedName: t.cleanedDescription,
                normalizedName: normalizeString(t.description, cleaningKeywords),
                amount: t.amount,
                date: t.date,
                originalAmount: t.originalAmount,
                contributionType: t.contributionType
            }));

            if (contributors.length > 0) {
                setContributorFiles(prev => {
                    const other = prev.filter(f => f.churchId !== churchId);
                    return [...other, { churchId, content, fileName, contributors }];
                });
                showToast(`Lista carregada (${result.method}).`, 'success');
            } else {
                showToast("Formato de lista não reconhecido. Use CSV ou Excel padronizado.", "error");
            }
        } catch (e: any) {
            showToast("Erro ao ler o arquivo: " + e.message, "error");
        } finally {
            setIsLoading(false);
        }
    }, [cleaningKeywords, setContributorFiles, showToast, setIsLoading, fileModels]);

    const handleTrainingSuccess = useCallback((model: FileModel, processedData: Transaction[]) => {
        if (!pendingTraining) return;

        const { type, entityId, content, fileName, rawFile } = pendingTraining;

        if (type === 'statement') {
            setBankStatementFile({ 
                bankId: entityId, 
                content, 
                fileName, 
                rawFile,
                processedTransactions: processedData 
            });
            showToast("Extrato processado e salvo!", "success");
        } else {
            const contributors: Contributor[] = processedData.map(t => ({
                name: t.description,
                cleanedName: t.cleanedDescription,
                normalizedName: normalizeString(t.description, cleaningKeywords),
                amount: t.amount,
                date: t.date,
                originalAmount: t.originalAmount,
                contributionType: t.contributionType
            }));

            setContributorFiles(prev => {
                const other = prev.filter(f => f.churchId !== entityId);
                return [...other, { churchId: entityId, content, fileName, contributors }];
            });
            showToast("Lista de contribuintes salva!", "success");
        }

        setPendingTraining(null);
    }, [pendingTraining, cleaningKeywords, setBankStatementFile, setContributorFiles, showToast]);

    const openLabManually = useCallback((targetFile?: { content: string, fileName: string, type: 'statement' | 'contributor', id: string, rawFile?: File }) => {
        if (targetFile) {
            setPendingTraining({
                content: targetFile.content,
                fileName: targetFile.fileName,
                type: targetFile.type,
                entityId: targetFile.id,
                rawFile: targetFile.rawFile
            });
        } else if (bankStatementFile) {
            setPendingTraining({
                content: bankStatementFile.content,
                fileName: bankStatementFile.fileName,
                type: 'statement',
                entityId: bankStatementFile.bankId,
                rawFile: bankStatementFile.rawFile
            });
        } else {
            showToast("Carregue um arquivo primeiro.", "error");
        }
    }, [bankStatementFile, showToast]);

    const removeBankStatementFile = useCallback(() => setBankStatementFile(null), [setBankStatementFile]);
    const removeContributorFile = useCallback((churchId: string) => {
        setContributorFiles(prev => prev.filter(f => f.churchId !== churchId));
    }, [setContributorFiles]);

    // Limpa apenas os arquivos (usado ao abrir um relatório salvo para evitar estado sujo)
    const clearFiles = useCallback(() => {
        setBankStatementFile(null);
        setContributorFiles([]);
    }, [setBankStatementFile, setContributorFiles]);

    // Função para limpar tudo e iniciar nova conciliação
    const resetReconciliation = useCallback(() => {
        setBankStatementFile(null);
        setContributorFiles([]);
        setMatchResults([]);
        setReportPreviewData(null);
        setHasActiveSession(false);
        setActiveReportId(null); // Limpa o ID do relatório ativo
        setManualIdentificationTx(null);
        setBulkIdentificationTxs(null);
        setManualMatchState(null);
        setDivergenceConfirmation(null);
        setAiSuggestion(null);
        showToast("Ambiente limpo para nova conciliação.", "success");
    }, [setBankStatementFile, setContributorFiles, setMatchResults, setReportPreviewData, setHasActiveSession, showToast, setActiveReportId]);

    // --- RECONCILIATION ENGINE JIT (Just-In-Time) ---
    const handleCompare = useCallback(async () => {
        if (!bankStatementFile) return;
        setIsLoading(true);

        try {
            // 1. REPROCESSAMENTO AUTOMÁTICO DO EXTRATO
            // Reprocessa para aplicar as configurações mais recentes (modelos e keywords)
            const stmtResult = processFileContent(bankStatementFile.content, bankStatementFile.fileName, fileModels, cleaningKeywords);
            const activeTransactions = stmtResult.transactions;

            if (activeTransactions.length === 0) {
                throw new Error("O extrato não gerou transações válidas. Verifique o arquivo.");
            }

            setBankStatementFile(prev => prev ? { ...prev, processedTransactions: activeTransactions } : null);

            let filteredTransactions = activeTransactions;
            if (comparisonType === 'income') filteredTransactions = activeTransactions.filter(t => t.amount > 0);
            else if (comparisonType === 'expenses') filteredTransactions = activeTransactions.filter(t => t.amount < 0);

            // 2. REPROCESSAMENTO AUTOMÁTICO DAS LISTAS DE CONTRIBUINTES
            const contributorData = contributorFiles.map(cf => {
                const church = churches.find(c => c.id === cf.churchId) || PLACEHOLDER_CHURCH;

                const listResult = processFileContent(cf.content, cf.fileName, fileModels, cleaningKeywords);
                const currentContributors = listResult.transactions.map(t => ({
                    name: t.description,
                    cleanedName: t.cleanedDescription,
                    normalizedName: normalizeString(t.description, cleaningKeywords),
                    amount: t.amount,
                    date: t.date,
                    originalAmount: t.originalAmount,
                    contributionType: t.contributionType
                }));

                return {
                    church,
                    contributors: currentContributors
                };
            });

            // 3. EXECUTAR O MATCHING
            const results = matchTransactions(
                filteredTransactions, 
                contributorData, 
                { similarityThreshold: similarityLevel, dayTolerance }, 
                learnedAssociations, 
                churches, 
                cleaningKeywords // Usa a lista combinada para matching também
            );

            setMatchResults(results);
            setReportPreviewData({
                // CORREÇÃO: Incluir itens PENDENTE (mesmo com valor 0) no relatório de entradas
                income: groupResultsByChurch(results.filter(r => r.transaction.amount > 0 || r.status === 'PENDENTE')),
                expenses: { 'all_expenses_group': results.filter(r => r.transaction.amount < 0) }
            });
            setHasActiveSession(true);

            // CORREÇÃO: NÃO resetar activeReportId aqui.
            // setActiveReportId(null); 

            setActiveView('reports');
            showToast("Conciliação finalizada!", 'success');

        } catch (e: any) {
            console.error(e);
            showToast(e.message || "Erro ao processar dados.", "error");
        } finally {
            setIsLoading(false);
        }
    }, [bankStatementFile, contributorFiles, churches, similarityLevel, dayTolerance, cleaningKeywords, learnedAssociations, setMatchResults, setReportPreviewData, setHasActiveSession, setActiveView, showToast, setIsLoading, comparisonType, setBankStatementFile, fileModels, setActiveReportId]);

    const updateReportData = useCallback((updatedRow: MatchResult, reportType: 'income' | 'expenses', idToRemove?: string) => {
        // 1. Atualiza lista plana (MatchResults)
        setMatchResults(prev => {
            let next = prev;
            // Se tiver ID para remover (Transação Fantasma Pendente), remove antes
            if (idToRemove) {
                next = next.filter(r => r.transaction.id !== idToRemove);
            }
            return next.map(r => r.transaction.id === updatedRow.transaction.id ? updatedRow : r);
        });

        // 2. Atualiza dados agrupados (ReportPreview)
        setReportPreviewData(prev => {
            if (!prev) return null;
            const newPreview = JSON.parse(JSON.stringify(prev));
            const targetGroup = reportType === 'expenses' ? newPreview.expenses : newPreview.income;

            if (reportType === 'income') {
                // LÓGICA DE ENTRADAS (Income)
                // Remove o item de qualquer grupo onde ele esteja (tanto o ID real quanto o ID fantasma)
                // Isso evita duplicação ao mover de 'unidentified' ou 'pendente' para uma igreja específica
                Object.keys(targetGroup).forEach(key => {
                    targetGroup[key] = targetGroup[key].filter((r: MatchResult) => {
                        const isTarget = r.transaction.id === updatedRow.transaction.id;
                        const isGhost = idToRemove && r.transaction.id === idToRemove;
                        return !isTarget && !isGhost;
                    });
                });

                // Adiciona o item atualizado ao grupo correto
                const currentChurchId = updatedRow.church.id || 'unidentified';
                if (!newPreview.income[currentChurchId]) newPreview.income[currentChurchId] = [];
                newPreview.income[currentChurchId].push(updatedRow);

            } else {
                // LÓGICA DE SAÍDAS (Expenses) - Mantém comportamento padrão de atualização in-place
                Object.keys(targetGroup).forEach(key => {
                    targetGroup[key] = targetGroup[key].map((r: MatchResult) => 
                        r.transaction.id === updatedRow.transaction.id ? updatedRow : r
                    );
                });
            }

            return newPreview;
        });
    }, [setMatchResults, setReportPreviewData]);

    const discardCurrentReport = useCallback(() => {
        setMatchResults([]);
        setReportPreviewData(null);
        setHasActiveSession(false);
        setActiveReportId(null);
        setActiveView('upload');
    }, [setMatchResults, setReportPreviewData, setHasActiveSession, setActiveView, setActiveReportId]);

    const closeManualIdentify = useCallback(() => {
        setManualIdentificationTx(null);
        setBulkIdentificationTxs(null);
    }, []);

    const openManualMatchModal = useCallback((record: MatchResult) => {
        const suggestions = matchResults.map(r => r.transaction); 
        setManualMatchState({ record, suggestions });
    }, [matchResults]);

    const closeManualMatchModal = useCallback(() => setManualMatchState(null), []);

    const confirmManualAssociation = useCallback((selectedTx: Transaction) => {
        if (!manualMatchState) return;
        const { record } = manualMatchState;

        // Se o registro original era PENDENTE, significa que era uma transação fantasma da lista.
        // Precisamos capturar esse ID para removê-lo, pois ele será substituído pela transação real do banco.
        const ghostIdToRemove = record.status === 'PENDENTE' ? record.transaction.id : undefined;

        const updatedResult: MatchResult = {
            ...record,
            transaction: selectedTx,
            status: 'IDENTIFICADO',
            matchMethod: 'MANUAL',
            similarity: 100
        };

        updateReportData(updatedResult, 'income', ghostIdToRemove);
        closeManualMatchModal();
        showToast("Associação manual aplicada.", "success");
    }, [manualMatchState, updateReportData, closeManualMatchModal, showToast]);

    const openDivergenceModal = useCallback((match: MatchResult) => setDivergenceConfirmation(match), []);
    const closeDivergenceModal = useCallback(() => setDivergenceConfirmation(null), []);

    const confirmDivergence = useCallback((divergentMatch: MatchResult) => {
        updateReportData({ ...divergentMatch, status: 'IDENTIFICADO' }, 'income');
        setDivergenceConfirmation(null);
    }, [updateReportData]);

    const rejectDivergence = useCallback((divergentMatch: MatchResult) => {
        if (divergentMatch.divergence?.expectedChurch) {
             const restored: MatchResult = {
                 ...divergentMatch,
                 church: divergentMatch.divergence.expectedChurch,
                 status: 'IDENTIFICADO'
             };
             updateReportData(restored, 'income');
        } else {
             updateReportData({ ...divergentMatch, status: 'NÃO IDENTIFICADO', church: PLACEHOLDER_CHURCH, contributor: null }, 'income');
        }
        setDivergenceConfirmation(null);
    }, [updateReportData]);

    const handleAnalyze = useCallback(async (transactionId: string) => {
        setLoadingAiId(transactionId);
        setTimeout(() => {
            setAiSuggestion({ id: transactionId, name: "Sugestão AI Simulada" });
            setLoadingAiId(null);
        }, 1500);
    }, []);

    return useMemo(() => ({
        bankStatementFile, contributorFiles, matchResults, setMatchResults, reportPreviewData, setReportPreviewData, hasActiveSession, setHasActiveSession,
        activeReportId, setActiveReportId, // EXPORTED
        pendingTraining, setPendingTraining, comparisonType, setComparisonType,
        handleStatementUpload, handleContributorsUpload, removeBankStatementFile, removeContributorFile, clearFiles, // EXPORTED
        handleCompare, updateReportData, discardCurrentReport, openLabManually,
        handleTrainingSuccess, resetReconciliation,
        manualIdentificationTx, setManualIdentificationTx,
        bulkIdentificationTxs, setBulkIdentificationTxs,
        closeManualIdentify,
        manualMatchState, setManualMatchState,
        openManualMatchModal, closeManualMatchModal, confirmManualAssociation,
        divergenceConfirmation, setDivergenceConfirmation,
        openDivergenceModal, closeDivergenceModal, confirmDivergence, rejectDivergence,
        loadingAiId, setLoadingAiId, aiSuggestion, setAiSuggestion, handleAnalyze
    }), [
        bankStatementFile, contributorFiles, matchResults, reportPreviewData, hasActiveSession, activeReportId, pendingTraining, comparisonType, 
        handleStatementUpload, handleContributorsUpload, removeBankStatementFile, removeContributorFile, clearFiles, handleCompare, updateReportData, discardCurrentReport, openLabManually, handleTrainingSuccess,
        setMatchResults, setReportPreviewData, setHasActiveSession, setActiveReportId, resetReconciliation,
        manualIdentificationTx, bulkIdentificationTxs, closeManualIdentify,
        manualMatchState, openManualMatchModal, closeManualMatchModal, confirmManualAssociation,
        divergenceConfirmation, openDivergenceModal, closeDivergenceModal, confirmDivergence, rejectDivergence,
        loadingAiId, aiSuggestion, handleAnalyze
    ]);
};

import React, { createContext, useState, useMemo, useCallback, useEffect, useRef } from 'react';
import { useAuth } from './AuthContext';
import { useUI } from './UIContext';
import { useReferenceData } from '../hooks/useReferenceData';
import { useReconciliation } from '../hooks/useReconciliation';
import { useReportManager } from '../hooks/useReportManager';
import { usePersistentState } from '../hooks/usePersistentState';
import {
    Transaction, Contributor, MatchResult, Bank, Church, ChurchFormData,
    DeletingItem, ComparisonType, GroupedReportData, SearchFilters, SavedReport,
    SavingReportState, LearnedAssociation, MatchMethod, FileModel
} from '../types';
import { groupResultsByChurch, PLACEHOLDER_CHURCH } from '../services/processingService';

import { supabase } from '../services/supabaseClient';
import { useTranslation } from './I18nContext';
import { LoadingSpinner } from '../components/shared/LoadingSpinner';
import { RecompareModal } from '../components/modals/RecompareModal';

interface AppContextType {
    // Data State (from useReferenceData)
    banks: Bank[];
    churches: Church[];
    fileModels: FileModel[];
    fetchModels: () => Promise<void>;
    setBanks: React.Dispatch<React.SetStateAction<Bank[]>>;
    setChurches: React.Dispatch<React.SetStateAction<Church[]>>;
    similarityLevel: number;
    setSimilarityLevel: React.Dispatch<React.SetStateAction<number>>;
    dayTolerance: number;
    setDayTolerance: React.Dispatch<React.SetStateAction<number>>;
    customIgnoreKeywords: string[]; 
    effectiveIgnoreKeywords: string[]; 
    addIgnoreKeyword: (keyword: string) => void;
    removeIgnoreKeyword: (keyword: string) => void;
    contributionKeywords: string[];
    addContributionKeyword: (keyword: string) => void;
    removeContributionKeyword: (keyword: string) => void;
    learnedAssociations: LearnedAssociation[];

    // Edit States
    editingBank: Bank | null;
    editingChurch: Church | null;
    openEditBank: (bank: Bank) => void;
    closeEditBank: () => void;
    updateBank: (bankId: string, name: string) => void;
    addBank: (name: string) => Promise<boolean>;
    openEditChurch: (church: Church) => void;
    closeEditChurch: () => void;
    updateChurch: (churchId: string, data: ChurchFormData) => void;
    addChurch: (data: ChurchFormData) => Promise<boolean>;

    // Reconciliation State (from useReconciliation)
    bankStatementFile: { bankId: string, content: string, fileName: string, rawFile?: File } | null;
    contributorFiles: { churchId: string; content: string; fileName: string; contributors?: Contributor[] }[];
    matchResults: MatchResult[];
    setMatchResults: React.Dispatch<React.SetStateAction<MatchResult[]>>;
    reportPreviewData: { income: GroupedReportData; expenses: GroupedReportData } | null;
    setReportPreviewData: React.Dispatch<React.SetStateAction<{ income: GroupedReportData; expenses: GroupedReportData } | null>>;
    comparisonType: ComparisonType;
    setComparisonType: React.Dispatch<React.SetStateAction<ComparisonType>>;
    hasActiveSession: boolean;
    isCompareDisabled: boolean;
    pendingTraining: any;
    setPendingTraining: (val: any) => void;
    activeReportId: string | null;

    // Reconciliation Actions
    openLabManually: (targetFile?: { content: string, fileName: string, type: 'statement' | 'contributor', id: string, rawFile?: File }) => void;
    handleStatementUpload: (content: string, fileName: string, bankId: string, rawFile: File) => void;
    handleContributorsUpload: (content: string, fileName: string, churchId: string) => void;
    handleTrainingSuccess: (model: FileModel, data: Transaction[]) => void;
    removeBankStatementFile: () => void;
    removeContributorFile: (churchId: string) => void;
    handleCompare: () => void;
    handleBackToSettings: () => void;
    updateReportData: (updatedRow: MatchResult, reportType: 'income' | 'expenses', idToRemove?: string) => void;
    discardCurrentReport: () => void;
    resetReconciliation: () => void; // NOVO

    // Manual Operations State & Handlers
    manualIdentificationTx: Transaction | null;
    setManualIdentificationTx: React.Dispatch<React.SetStateAction<Transaction | null>>;
    bulkIdentificationTxs: Transaction[] | null;
    setBulkIdentificationTxs: React.Dispatch<React.SetStateAction<Transaction[] | null>>;

    openManualIdentify: (transactionId: string) => void;
    openBulkManualIdentify: (transactions: Transaction[]) => void;
    closeManualIdentify: () => void;
    confirmManualIdentification: (transactionId: string, churchId: string) => void;
    confirmBulkManualIdentification: (transactionIds: string[], churchId: string) => void;

    manualMatchState: { record: MatchResult, suggestions: Transaction[] } | null;
    setManualMatchState: React.Dispatch<React.SetStateAction<{ record: MatchResult, suggestions: Transaction[] } | null>>;
    openManualMatchModal: (recordToMatch: MatchResult) => void;
    closeManualMatchModal: () => void;
    confirmManualAssociation: (selectedTx: Transaction) => void;

    // Smart Edit (NEW)
    smartEditTarget: MatchResult | null;
    openSmartEdit: (match: MatchResult) => void;
    closeSmartEdit: () => void;
    saveSmartEdit: (updatedMatch: MatchResult) => void;

    divergenceConfirmation: MatchResult | null;
    setDivergenceConfirmation: React.Dispatch<React.SetStateAction<MatchResult | null>>;
    openDivergenceModal: (match: MatchResult) => void;
    closeDivergenceModal: () => void;
    confirmDivergence: (divergentMatch: MatchResult) => void;
    rejectDivergence: (divergentMatch: MatchResult) => void;

    learnAssociation: (matchResult: MatchResult) => Promise<void>;
    findMatchResult: (transactionId: string) => MatchResult | undefined;

    // AI
    loadingAiId: string | null;
    aiSuggestion: { id: string, name: string } | null;
    handleAnalyze: (transaction: Transaction, candidates: Contributor[]) => void;

    // Recompare Modal
    isRecompareModalOpen: boolean;
    openRecompareModal: () => void;
    closeRecompareModal: () => void;

    // Reports & Search (from useReportManager)
    savedReports: SavedReport[];
    maxSavedReports: number; // NOVO: Limite de relatórios
    searchFilters: SearchFilters;
    setSearchFilters: React.Dispatch<React.SetStateAction<SearchFilters>>;
    isSearchFiltersOpen: boolean;
    openSearchFilters: () => void;
    closeSearchFilters: () => void;
    clearSearchFilters: () => void;
    allHistoricalResults: MatchResult[];

    savingReportState: SavingReportState | null;
    openSaveReportModal: (state: SavingReportState) => void;
    closeSaveReportModal: () => void;
    confirmSaveReport: (name: string) => void;
    viewSavedReport: (reportId: string) => void;
    updateSavedReportName: (reportId: string, newName: string) => void;
    saveFilteredReport: (results: MatchResult[]) => void;
    saveCurrentReportChanges: () => void; // Nova função

    // Global
    deletingItem: DeletingItem | null;
    openDeleteConfirmation: (item: DeletingItem) => void;
    closeDeleteConfirmation: () => void;
    confirmDeletion: () => void;
    initialDataLoaded: boolean;
    isSyncing: boolean; // NOVO: Estado para indicar sincronização em background
    summary: {
        autoConfirmed: { count: number; value: number; };
        manualConfirmed: { count: number; value: number; };
        pending: { count: number; value: number; };
        identifiedCount: number;
        unidentifiedCount: number;
        totalValue: number;
        valuePerChurch: [string, number][];
        isHistorical: boolean;
        methodBreakdown: Record<MatchMethod, number>;
    };
    isPaymentModalOpen: boolean;
    openPaymentModal: () => void;
    closePaymentModal: () => void;
}

export const AppContext = createContext<AppContextType>(null!);

export const AppProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
    const { user, systemSettings, incrementAiUsage } = useAuth();
    const { t } = useTranslation();
    const { showToast, setIsLoading, setActiveView } = useUI();

    const referenceData = useReferenceData(user, showToast);
    const reportManager = useReportManager(user, showToast);

    const effectiveIgnoreKeywords = useMemo(() => {
        return systemSettings.globalIgnoreKeywords || [];
    }, [systemSettings.globalIgnoreKeywords]);

    const reconciliation = useReconciliation({
        user, 
        churches: referenceData.churches,
        banks: referenceData.banks,
        fileModels: [],
        similarityLevel: referenceData.similarityLevel,
        dayTolerance: referenceData.dayTolerance,
        customIgnoreKeywords: effectiveIgnoreKeywords,
        contributionKeywords: referenceData.contributionKeywords,
        learnedAssociations: referenceData.learnedAssociations,
        showToast, setIsLoading, setActiveView
    });

    const [initialDataLoaded, setInitialDataLoaded] = useState(true);
    const [isSyncing, setIsSyncing] = useState(false); // Inicializa sem sync

    const [deletingItem, setDeletingItem] = useState<DeletingItem | null>(null);
    const [isPaymentModalOpen, setIsPaymentModalOpen] = useState(false);
    const [isRecompareModalOpen, setIsRecompareModalOpen] = useState(false);

    const [smartEditTarget, setSmartEditTarget] = useState<MatchResult | null>(null);

    const userSuffix = user ? `-${user.id}` : '-guest';
    const [summary, setSummary] = usePersistentState(`identificapix-dashboard-summary-v6${userSuffix}`, {
        autoConfirmed: { count: 0, value: 0 },
        manualConfirmed: { count: 0, value: 0 },
        pending: { count: 0, value: 0 },
        identifiedCount: 0, unidentifiedCount: 0, totalValue: 0, valuePerChurch: [], isHistorical: false,
        methodBreakdown: { 'AUTOMATIC': 0, 'MANUAL': 0, 'LEARNED': 0, 'AI': 0, 'TEMPLATE': 0 }
    }, false);

    // Fetch de Dados (Background Sync) - NÃO BLOQUEANTE
    useEffect(() => {
        if (!user) return;
        const fetchData = async () => {
            // Usamos isSyncing para dar feedback sutil (ex: na sidebar) se necessário.
            setIsSyncing(true);

            try {
                // OTIMIZAÇÃO CRÍTICA (Resource Exhaustion Fix):
                // NÃO selecionamos a coluna 'data' (JSON pesado) na listagem inicial.
                // Isso evita o erro de "Exhausting multiple resources" no Supabase Nano.
                const [churchesRes, banksRes, reportsRes] = await Promise.all([
                    supabase.from('churches').select('*').order('name'),
                    supabase.from('banks').select('*').order('name'),
                    supabase.from('saved_reports')
                        .select('id, name, created_at, record_count, user_id') // SEM 'data'
                        .eq('user_id', user.id)
                        .order('created_at', { ascending: false }),
                ]);

                if (churchesRes.data) referenceData.setChurches(churchesRes.data as any);
                if (banksRes.data) referenceData.setBanks(banksRes.data as any);

                if (reportsRes.data) {
                    reportManager.setSavedReports((reportsRes.data || []).map(r => ({ 
                        id: r.id, 
                        name: r.name, 
                        createdAt: r.created_at, 
                        recordCount: r.record_count, 
                        user_id: r.user_id, 
                        data: null // Lazy Load: Iniciamos sem dados pesados
                    })));
                }
            } catch (err) { console.error('Background sync failed', err); } 
            finally { 
                setIsSyncing(false); 
                setInitialDataLoaded(true); 
            }
        };
        fetchData();
    }, [user?.id]);

    const resultsHash = JSON.stringify(reconciliation.matchResults.map(r => r.transaction.id + r.status));
    const reportsHash = reportManager.savedReports.length;

    useEffect(() => {
        const timer = setTimeout(() => {
            let resultsToProcess = reconciliation.matchResults;
            let isHistorical = false;
            // No modo Lazy Load, o Dashboard histórico fica limitado aos dados já carregados na memória
            // ou apenas à sessão ativa, para evitar crash.
            if (resultsToProcess.length === 0 && reportManager.savedReports.length > 0) {
                resultsToProcess = reportManager.savedReports.flatMap(report => report.data?.results || []);
                isHistorical = true;
            }
            const autoConfirmed = resultsToProcess.filter(r => r.status === 'IDENTIFICADO' && (r.matchMethod === 'AUTOMATIC' || r.matchMethod === 'LEARNED' || !r.matchMethod));
            const manualConfirmed = resultsToProcess.filter(r => r.status === 'IDENTIFICADO' && (r.matchMethod === 'MANUAL' || r.matchMethod === 'AI'));
            const pending = resultsToProcess.filter(r => r.status === 'NÃO IDENTIFICADO');
            const valuePerChurch = new Map<string, number>();
            const methodBreakdown: Record<MatchMethod, number> = { 'AUTOMATIC': 0, 'MANUAL': 0, 'LEARNED': 0, 'AI': 0, 'TEMPLATE': 0 };
            resultsToProcess.forEach(r => {
                if (r.status === 'IDENTIFICADO') {
                    if (r.church && r.church.name !== '---' && r.transaction.amount > 0) {
                        const current = valuePerChurch.get(r.church.name) || 0;
                        valuePerChurch.set(r.church.name, current + r.transaction.amount);
                    }
                    const method = r.matchMethod || 'AUTOMATIC';
                    if (methodBreakdown[method] !== undefined) methodBreakdown[method]++;
                }
            });
            const newTotal = resultsToProcess.reduce((sum, r) => sum + r.transaction.amount, 0);
            setSummary(prev => ({
                autoConfirmed: { count: autoConfirmed.length, value: autoConfirmed.reduce((sum, r) => sum + r.transaction.amount, 0) },
                manualConfirmed: { count: manualConfirmed.length, value: manualConfirmed.reduce((sum, r) => sum + r.transaction.amount, 0) },
                pending: { count: pending.length, value: pending.reduce((sum, r) => sum + r.transaction.amount, 0) },
                identifiedCount: autoConfirmed.length + manualConfirmed.length,
                unidentifiedCount: pending.length, totalValue: newTotal,
                valuePerChurch: Array.from(valuePerChurch.entries()).sort((a, b) => b[1] - a[1]),
                isHistorical, methodBreakdown
            }));
        }, 300);
        return () => clearTimeout(timer);
    }, [resultsHash, reportsHash]);

    const handleBackToSettings = useCallback(() => setActiveView('upload'), [setActiveView]);
    const openDeleteConfirmation = useCallback((item: DeletingItem) => setDeletingItem(item), []);
    const closeDeleteConfirmation = useCallback(() => setDeletingItem(null), []);
    const confirmDeletion = useCallback(async () => {
        if (!deletingItem) return;
        if (deletingItem.type === 'report-row') {
             reconciliation.setReportPreviewData(prev => {
                 if (!prev) return null;
                 const newPreview = { ...prev };
                 const targetGroup = deletingItem.meta?.reportType === 'expenses' ? newPreview.expenses : newPreview.income;
                 Object.keys(targetGroup).forEach(key => { targetGroup[key] = targetGroup[key].filter(r => r.transaction.id !== deletingItem.id); });
                 return newPreview;
             });
             reconciliation.setMatchResults(prev => prev.filter(r => r.transaction.id !== deletingItem.id));
        } else if (deletingItem.type === 'report-group') {
             reconciliation.setReportPreviewData(prev => {
                 if (!prev) return null;
                 const newPreview = { ...prev };
                 const targetGroup = deletingItem.meta?.reportType === 'expenses' ? newPreview.expenses : newPreview.income;
                 if (targetGroup[deletingItem.id]) {
                     const idsToRemove = targetGroup[deletingItem.id].map(r => r.transaction.id);
                     delete targetGroup[deletingItem.id];
                     reconciliation.setMatchResults(prev => prev.filter(r => !idsToRemove.includes(r.transaction.id)));
                 }
                 return newPreview;
             });
        } else if (deletingItem.type === 'bank') {
            referenceData.setBanks(prev => prev.filter(b => b.id !== deletingItem.id));
            await supabase.from('banks').delete().eq('id', deletingItem.id);
        } else if (deletingItem.type === 'church') {
            referenceData.setChurches(prev => prev.filter(c => c.id !== deletingItem.id));
            await supabase.from('churches').delete().eq('id', deletingItem.id);
        } else if (deletingItem.type === 'report-saved') {
            reportManager.setSavedReports(prev => prev.filter(r => r.id !== deletingItem.id));
            await supabase.from('saved_reports').delete().eq('id', deletingItem.id);
        } else if (deletingItem.type === 'uploaded-files') { reconciliation.removeBankStatementFile(); }
        closeDeleteConfirmation();
        showToast("Ação realizada com sucesso.");
    }, [deletingItem, user, referenceData, reportManager, reconciliation, showToast, closeDeleteConfirmation]);

    const viewSavedReport = useCallback(async (reportId: string) => {
        setIsLoading(true);
        try {
            let report = reportManager.savedReports.find(r => r.id === reportId);
            if (!report) return;

            // LAZY LOAD LOGIC: Busca o conteúdo 'data' apenas se ele estiver vazio
            if (!report.data) {
                const { data: reportContent, error } = await supabase
                    .from('saved_reports')
                    .select('data')
                    .eq('id', reportId)
                    .single();

                if (error) throw error;

                if (reportContent) {
                    const parsedData = typeof reportContent.data === 'string' 
                        ? JSON.parse(reportContent.data) 
                        : reportContent.data;

                    report = { ...report, data: parsedData };
                    // Atualiza cache local
                    reportManager.setSavedReports(prev => prev.map(r => r.id === reportId ? report! : r));
                }
            }

            if (!report.data) throw new Error("Conteúdo do relatório vazio.");

            // LIMPEZA CRÍTICA: Reseta os arquivos de upload para evitar estado "preso"
            // Isso garante que se o usuário for para a tela de Upload, ela estará limpa para novos arquivos
            // e não bloqueada por arquivos da sessão anterior.
            reconciliation.clearFiles();

            const validResults = report.data.results.map((r: any) => ({ ...r, church: r.church || PLACEHOLDER_CHURCH }));
            reconciliation.setMatchResults(validResults);
            reconciliation.setReportPreviewData({
                income: groupResultsByChurch(validResults.filter((r: any) => r.transaction.amount > 0 || r.status === 'PENDENTE')),
                expenses: { 'all_expenses_group': validResults.filter((r: any) => r.transaction.amount < 0) }
            });
            reconciliation.setHasActiveSession(true); 
            reconciliation.setActiveReportId(reportId); // CRÍTICO: Define qual relatório está sendo editado
            setActiveView('reports'); 
        } catch (error: any) {
            console.error(error);
            showToast("Erro ao abrir relatório: " + error.message, "error");
        } finally {
            setIsLoading(false);
        }
    }, [reportManager.savedReports, reconciliation, setActiveView, setIsLoading, showToast]);

    // Nova função para salvar as alterações do relatório ativo
    const saveCurrentReportChanges = useCallback(() => {
        const reportId = reconciliation.activeReportId;
        if (!reportId) {
            showToast("Nenhum relatório salvo ativo para atualizar.", "error");
            return;
        }
        reportManager.overwriteSavedReport(reportId, reconciliation.matchResults);
    }, [reconciliation.activeReportId, reconciliation.matchResults, reportManager, showToast]);

    const findMatchResult = useCallback((transactionId: string) => reconciliation.matchResults.find(r => r.transaction.id === transactionId) || reportManager.allHistoricalResults.find(r => r.transaction.id === transactionId), [reconciliation.matchResults, reportManager.allHistoricalResults]);

    const openManualIdentify = useCallback((transactionId: string) => {
        const result = findMatchResult(transactionId);
        if (result) reconciliation.setManualIdentificationTx(result.transaction);
    }, [findMatchResult, reconciliation]);

    const openBulkManualIdentify = useCallback((transactions: Transaction[]) => { reconciliation.setBulkIdentificationTxs(transactions); }, [reconciliation]);

    const confirmManualIdentification = useCallback((transactionId: string, churchId: string) => {
        const church = referenceData.churches.find(c => c.id === churchId);
        const result = findMatchResult(transactionId);
        if (church && result) {
            const updated: MatchResult = { ...result, status: 'IDENTIFICADO', church, contributor: { id: `manual-${transactionId}`, name: result.transaction.cleanedDescription || result.transaction.description, amount: result.transaction.amount }, matchMethod: 'MANUAL', similarity: 100, contributorAmount: result.transaction.amount };
            if (reconciliation.matchResults.some(r => r.transaction.id === transactionId)) reconciliation.updateReportData(updated, 'income');
            else reportManager.updateSavedReportTransaction(transactionId, updated);
            reconciliation.closeManualIdentify(); 
            // Feedback modificado para não confundir com salvamento em banco
            showToast('Identificação realizada.', 'success');
        }
    }, [referenceData.churches, findMatchResult, reconciliation, reportManager, showToast]);

    const confirmBulkManualIdentification = useCallback((transactionIds: string[], churchId: string) => {
        const church = referenceData.churches.find(c => c.id === churchId);
        if (!church) return;

        transactionIds.forEach(id => {
            const result = findMatchResult(id);
            if (result) {
                const updated: MatchResult = { 
                    ...result, 
                    status: 'IDENTIFICADO', 
                    church, 
                    contributor: { id: `manual-${id}`, name: result.transaction.cleanedDescription || result.transaction.description, amount: result.transaction.amount }, 
                    matchMethod: 'MANUAL', 
                    similarity: 100, 
                    contributorAmount: result.transaction.amount 
                };
                if (reconciliation.matchResults.some(r => r.transaction.id === id)) reconciliation.updateReportData(updated, 'income');
                else reportManager.updateSavedReportTransaction(id, updated);
            }
        });
        reconciliation.closeManualIdentify();
        showToast(`${transactionIds.length} transações identificadas.`, 'success');
    }, [referenceData.churches, findMatchResult, reconciliation, reportManager, showToast]);

    const openSmartEdit = useCallback((match: MatchResult) => {
        setSmartEditTarget(match);
    }, []);

    const closeSmartEdit = useCallback(() => {
        setSmartEditTarget(null);
        reconciliation.setAiSuggestion(null);
    }, [reconciliation]);

    const saveSmartEdit = useCallback((updatedMatch: MatchResult) => {
        if (reconciliation.matchResults.some(r => r.transaction.id === updatedMatch.transaction.id)) {
            // Se for uma edição de match reverso, precisamos remover o ID fantasma
            const ghostId = smartEditTarget?.status === 'PENDENTE' ? smartEditTarget.transaction.id : undefined;
            reconciliation.updateReportData(updatedMatch, 'income', ghostId);
        } else {
            reportManager.updateSavedReportTransaction(updatedMatch.transaction.id, updatedMatch);
        }
        // Feedback modificado para não confundir com salvamento em banco
        showToast("Edição aplicada na tabela.", "success");
        setSmartEditTarget(null);
        reconciliation.setAiSuggestion(null);
    }, [reconciliation, reportManager, showToast, smartEditTarget]);

    const handleAnalyze = useCallback(async (transaction: Transaction, candidates: Contributor[]) => {
        reconciliation.setLoadingAiId(transaction.id);
        try {
            const candidateNames = candidates.slice(0, 50).map(c => c.name);
            const response = await fetch('/api/ai/suggestion', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    transactionDescription: transaction.description,
                    contributorNames: candidateNames
                })
            });

            if (!response.ok) throw new Error('Falha na API de IA');
            const data = await response.json();
            const suggestionText = data.text;

            if (suggestionText && !suggestionText.includes("Nenhuma sugestão clara")) {
                reconciliation.setAiSuggestion({ id: transaction.id, name: suggestionText });
                incrementAiUsage(); 
            } else {
                reconciliation.setAiSuggestion(null);
            }
        } catch (error) {
            console.error("Erro na análise IA:", error);
            showToast("Não foi possível obter sugestão da IA.", "error");
        } finally {
            reconciliation.setLoadingAiId(null);
        }
    }, [incrementAiUsage, showToast, reconciliation]);

    const value = useMemo(() => ({
        ...referenceData, ...reconciliation, isCompareDisabled: !reconciliation.bankStatementFile,
        effectiveIgnoreKeywords, 
        openManualIdentify, openBulkManualIdentify, confirmManualIdentification, confirmBulkManualIdentification, findMatchResult,
        ...reportManager, viewSavedReport, handleBackToSettings, deletingItem, openDeleteConfirmation,
        closeDeleteConfirmation, confirmDeletion, initialDataLoaded, isSyncing, summary, isPaymentModalOpen,
        openPaymentModal: () => setIsPaymentModalOpen(true), closePaymentModal: () => setIsPaymentModalOpen(false),
        isRecompareModalOpen, openRecompareModal: () => setIsRecompareModalOpen(true), closeRecompareModal: () => setIsRecompareModalOpen(false),
        smartEditTarget, openSmartEdit, closeSmartEdit, saveSmartEdit, handleAnalyze,
        saveCurrentReportChanges
    }), [referenceData, reconciliation, effectiveIgnoreKeywords, reportManager, viewSavedReport, handleBackToSettings, deletingItem, openDeleteConfirmation, closeDeleteConfirmation, confirmDeletion, initialDataLoaded, isSyncing, summary, isPaymentModalOpen, isRecompareModalOpen, openManualIdentify, openBulkManualIdentify, confirmManualIdentification, confirmBulkManualIdentification, findMatchResult, smartEditTarget, openSmartEdit, closeSmartEdit, saveSmartEdit, handleAnalyze, saveCurrentReportChanges]);

    return <AppContext.Provider value={value}>{children}<RecompareModal /></AppContext.Provider>;
};

import React, { useContext } from 'react';
import { AppContext } from '../../contexts/AppContext';
import { useTranslation } from '../../contexts/I18nContext';
import { ArrowsRightLeftIcon, DocumentArrowDownIcon, UploadIcon } from '../Icons';
import { ComparisonType } from '../../types';

export const ComparisonSettingsForm: React.FC = () => {
    const { 
        similarityLevel, 
        setSimilarityLevel, 
        dayTolerance, 
        setDayTolerance, 
        handleCompare, 
        isCompareDisabled,
        comparisonType,
        setComparisonType,
        bankStatementFile,
        activeReportId // Adicionado para verificação
    } = useContext(AppContext);
    const { t, language } = useTranslation();

    // LÓGICA CORRIGIDA:
    // O botão habilita se:
    // 1. Tiver arquivo de extrato carregado (Fluxo Normal)
    // OU
    // 2. Estiver editando um relatório salvo (activeReportId) - Fluxo Aditivo
    const canProcess = !!bankStatementFile || !!activeReportId;

    // Mantém a lógica específica de 'income' se necessário, mas prioriza a regra acima
    const finalIsCompareDisabled = comparisonType === 'income' ? (!canProcess && isCompareDisabled) : !canProcess;

    const ComparisonOption = ({ value, label, colorTheme, icon: Icon }: { value: ComparisonType, label: string, colorTheme: 'emerald' | 'rose' | 'blue', icon: any }) => {
        const isSelected = comparisonType === value;

        const themes = {
            emerald: { // Entradas (Green)
                active: 'bg-emerald-100 text-emerald-700 border-emerald-200 dark:bg-emerald-500/20 dark:text-emerald-300 dark:border-emerald-500/30',
                inactive: 'text-slate-500 hover:text-emerald-600 hover:bg-emerald-50 dark:text-slate-400 dark:hover:text-emerald-300 dark:hover:bg-emerald-500/10'
            },
            rose: { // Saídas (Red/Rose)
                active: 'bg-rose-100 text-rose-700 border-rose-200 dark:bg-rose-500/20 dark:text-rose-300 dark:border-rose-500/30',
                inactive: 'text-slate-500 hover:text-rose-600 hover:bg-rose-50 dark:text-slate-400 dark:hover:text-rose-300 dark:hover:bg-rose-500/10'
            },
            blue: { // Ambos (Blue)
                active: 'bg-blue-100 text-blue-700 border-blue-200 dark:bg-blue-500/20 dark:text-blue-300 dark:border-blue-500/30',
                inactive: 'text-slate-500 hover:text-blue-600 hover:bg-blue-50 dark:text-slate-400 dark:hover:text-blue-300 dark:hover:bg-blue-500/10'
            }
        };

        const style = themes[colorTheme];

        return (
            <label 
                className={`
                    cursor-pointer relative flex items-center justify-center gap-1.5 px-3 py-1.5 text-[10px] font-bold rounded-full transition-all duration-200 border
                    ${isSelected 
                        ? `${style.active} shadow-sm` 
                        : `bg-white dark:bg-slate-800 border-slate-100 dark:border-slate-700 ${style.inactive}`
                    }
                `}
            >
                <Icon className={`w-3 h-3 ${isSelected ? '' : 'opacity-70'}`} />
                <input 
                    type="radio" 
                    name="comparisonType" 
                    value={value} 
                    checked={isSelected} 
                    onChange={(e) => setComparisonType(e.target.value as ComparisonType)} 
                    className="sr-only" 
                />
                <span className="uppercase tracking-wide">{label}</span>
            </label>
        );
    }

    return (
        <div className="animate-fade-in flex flex-col lg:flex-row items-center justify-between gap-3 w-full">

            {/* Left: Type Selection (Soft Pill Buttons) */}
            <div className="flex flex-wrap items-center justify-center md:justify-start gap-2">
                <ComparisonOption 
                    value="income" 
                    label={t('upload.income')} 
                    colorTheme="emerald" 
                    icon={DocumentArrowDownIcon} 
                />
                <ComparisonOption 
                    value="expenses" 
                    label={t('upload.expenses')} 
                    colorTheme="rose" 
                    icon={UploadIcon} 
                />
                <ComparisonOption 
                    value="both" 
                    label={t('upload.both')} 
                    colorTheme="blue" 
                    icon={ArrowsRightLeftIcon} 
                />
            </div>

            {/* Middle: Sliders (Refined) */}
            { (comparisonType === 'income' || comparisonType === 'both') && (
                <div className="flex flex-1 items-center justify-center gap-6 lg:gap-10 w-full lg:w-auto px-2">

                    {/* Similarity Slider */}
                    <div className="flex items-center gap-3 w-full max-w-[200px] group">
                        <span className="text-[9px] font-bold text-slate-400 uppercase w-10 text-right">Similar</span>
                        <div className="flex-1 relative h-2 bg-slate-100 dark:bg-slate-700/50 rounded-full overflow-hidden border border-slate-200 dark:border-slate-600">
                            <div className="absolute top-0 left-0 h-full bg-brand-blue rounded-full transition-all duration-300" style={{ width: `${similarityLevel}%` }}></div>
                            <input 
                                type="range" min="10" max="100" value={similarityLevel} 
                                onChange={e => setSimilarityLevel(parseInt(e.target.value, 10))} 
                                className="absolute inset-0 w-full h-full opacity-0 cursor-pointer" 
                            />
                        </div>
                        {/* High Visibility Badge */}
                        <div className="flex items-center justify-center min-w-[3.5rem] px-2 py-1 bg-blue-100 dark:bg-blue-900/30 border border-blue-200 dark:border-blue-800 rounded-lg shadow-sm">
                            <span className="text-xs font-black text-brand-blue dark:text-blue-400">{similarityLevel}%</span>
                        </div>
                    </div>

                    {/* Tolerance Slider */}
                    <div className="flex items-center gap-3 w-full max-w-[200px] group">
                        <span className="text-[9px] font-bold text-slate-400 uppercase w-10 text-right">Tol.</span>
                        <div className="flex-1 relative h-2 bg-slate-100 dark:bg-slate-700/50 rounded-full overflow-hidden border border-slate-200 dark:border-slate-600">
                            <div className="absolute top-0 left-0 h-full bg-brand-teal rounded-full transition-all duration-300" style={{ width: `${(dayTolerance / 30) * 100}%` }}></div>
